UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('premier-rappel', 'Le premier rappel est un exercice fondamental pour établir une communication claire avec votre chien et assurer sa sécurité. Il consiste à faire revenir votre chien vers vous lorsqu''il est appelé, renforçant ainsi votre lien et sa confiance. Cet exercice est la base de tous les autres rappels plus complexes.', NULL, NULL, 'Premier rappel', 'Venir quand on appelle', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien se retourne immédiatement à l''appel, se dirige vers le handler de manière directe et rapide, et arrive avec enthousiasme pour recevoir sa récompense.', 'Le chien ne montre aucun signe d''écoute, ignore systématiquement les appels, ou associe l''appel à une expérience négative (punition, fin d''un jeu amusant).', 'Depuis un environnement contrôlé et sans distractions, demandez au chien de venir. Observez sa réaction et sa rapidité à répondre à l''appel. Renouvelez plusieurs fois et augmentez progressivement la distance et les distractions.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/premier-rappel.png'),
('chiot-toilettage', 'Le premier toilettage de votre chiot est une étape cruciale pour qu''il développe une relation positive avec ces soins. Cet exercice vise à le familiariser en douceur avec les sensations et les manipulations associées au toilettage. L''objectif est de rendre cette expérience agréable et de prévenir les angoisses futures.', NULL, NULL, 'Premier toilettage', 'Habituer au brossage et au bain', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chiot reste calme et détendu pendant les manipulations douces et courtes. Il accepte le contact sur différentes parties du corps sans tension excessive. Il associe les outils à des moments agréables.', 'Le chiot montre des signes clairs de stress, d''anxiété, de peur ou de douleur, malgré les efforts pour le rassurer. Il tente activement de fuir ou de mordre. La séance devient contre-productive.', 'Observer attentivement le comportement du chiot pour détecter tout signe de stress, de peur ou de douleur. Se concentrer sur les réactions positives (calme, détente, curiosité) et l''absence de réactions négatives.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chiot-toilettage.png'),
('premiere-laisse', 'L''exercice de la ''Première Laisse'' vise à familiariser le chiot ou le nouveau chien avec la sensation de porter une laisse et un collier ou harnais. L''objectif est d''associer ces nouveaux accessoires à des expériences positives et de le préparer aux futures promenades. Cet exercice doit être court, ludique et progressif pour éviter toute appréhension.', NULL, NULL, 'Première laisse', 'Accepter le collier et la laisse', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte de porter le collier ou harnais pendant au moins 5 minutes sans tenter de l''enlever et fait au moins 5-10 pas avec la laisse tenue lâchement sans être tiré. Le chien montre des signes de décontraction et d''intérêt pour l''activité.', 'Le chien manifeste une peur ou une anxiété marquée, refuse catégoriquement de coopérer, ou montre des signes de douleur physique. Toute agressivité envers le matériel ou le handler est un signal d''arrêt immédiat.', 'À chaque étape, observez attentivement les réactions du chien (langage corporel, vocalisations). Si le chien montre des signes de stress (halètement excessif, bâillements, oreilles en arrière, queue basse, tentative de fuite), la séance est terminée. Le chien doit accepter le matériel et faire quelques pas sans résistance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/premiere-laisse.png'),
('chiot-voiture', 'Cet exercice vise à habituer votre chien aux trajets en voiture de manière positive et progressive. L''objectif est de réduire l''anxiété et d''associer la voiture à une expérience agréable. Une bonne préparation et de la patience sont essentielles pour ce processus.', NULL, NULL, 'Premiers trajets en voiture', 'Habituer le chiot à la voiture', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien monte volontairement dans la voiture, reste calme pendant les trajets (même courts), et ne manifeste pas de signes d''anxiété ou de mal des transports excessifs.', 'Le chien montre une peur intense, une agressivité ou un mal des transports sévère et persistant malgré les tentatives d''adaptation, ou s''il y a un risque pour la sécurité du chien ou de l''humain.', 'Observer la réaction du chien à chaque étape : s''il reste calme, détendu et sans signes de stress, l''étape est validée. S''il montre de l''anxiété, revenir à l''étape précédente ou la modifier.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chiot-voiture.png'),
('prendre-temperature', 'La prise de température rectale est une procédure essentielle pour surveiller la santé de votre chien. Elle permet de détecter rapidement une fièvre ou une hypothermie, signes potentiels d''une maladie. Une bonne approche rendra l''expérience moins stressante pour vous et votre animal.', NULL, NULL, 'Prise de température', 'Accepter le thermomètre', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'La température est lue correctement, le chien reste relativement calme et coopératif pendant la procédure, le processus est terminé sans blessure ni stress excessif pour l''animal ou le handler.', 'Le chien montre des signes de douleur intense, de panique ou d''agressivité incontrôlable, ou si le handler ressent une gêne ou une peur importante. En cas de saignement ou de blessure évidente, arrêtez immédiatement et consultez un vétérinaire.', 'Observer la réaction du chien aux manipulations, la facilité d''insertion du thermomètre, le temps d''attente pour la lecture, et la propreté de la zone après l''exercice. Vérifier que le thermomètre fonctionne correctement avant de commencer.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/prendre-temperature.png'),
('protocole-relaxation', 'Le protocole de relaxation est un exercice essentiel pour aider votre chien à gérer son stress, son anxiété et son excitation. Il vise à lui apprendre à se calmer volontairement et à retrouver un état de repos sur commande. Cet exercice est particulièrement utile pour les chiens réactifs ou ayant du mal à se poser.', NULL, NULL, 'Protocole de relaxation', 'Détente complète sur tapis', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement la détente, baisse la tête, baille, ou se couche volontairement lorsqu''on lui demande ''détente'' dans divers contextes, et il maintient cet état plusieurs secondes.', 'Le chien montre des signes de stress excessif (halètement intense, tremblements, tentatives de fuite), ne parvient pas à se calmer malgré les efforts, ou si vous remarquez une dégradation de son bien-être général lié à l''exercice.', 'L''exercice est réussi lorsque le chien peut se détendre volontairement sur commande, même en présence de distractions modérées, et y rester pendant une durée raisonnable (ex: 30 secondes à 1 minute).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/protocole-relaxation.png'),
('puzzle-debutant', 'Cet exercice de puzzle pour débutants est conçu pour stimuler mentalement votre chien tout en renforçant votre lien. Il utilise des friandises cachées dans des objets simples pour encourager la résolution de problèmes et la patience. C''est une excellente introduction aux jouets interactifs et aux activités d''enrichissement canin.', NULL, NULL, 'Puzzle débutant', 'Résoudre un puzzle simple', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement et trouve les friandises plusieurs fois de manière autonome. Il montre de l''enthousiasme et de la curiosité pour l''exercice.', 'Le chien montre des signes de stress, de frustration évidente, ou un désintérêt total pour l''exercice. La séance atteint une durée de 10-15 minutes maximum.', 'Observer si le chien prend l''initiative de chercher les friandises une fois qu''il comprend le principe. Noter la durée pendant laquelle il reste engagé dans l''exercice.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/puzzle-debutant.png'),
('puzzle-expert', 'Le jeu ''Puzzle Expert'' est une activité d''enrichissement mental conçue pour stimuler l''intelligence de votre chien et le récompenser pour ses efforts. Il s''agit d''une série d''énigmes et de cachettes à découvrir, utilisant des friandises comme motivation principale. Cet exercice est idéal pour les chiens ayant déjà une bonne base en recherche d''objets et en résolution de problèmes simples.', NULL, NULL, 'Puzzle expert', 'Puzzle complexe multi-étapes', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement le puzzle, manipule le jouet ou le tapis de fouille avec intérêt pour obtenir les récompenses, et montre des signes de satisfaction (queue qui remue, halètement joyeux) lorsqu''il réussit à obtenir des friandises, sans montrer de frustration excessive.', 'Le chien montre des signes évidents de frustration (grogne, aboiements insistants, tentative de destruction agressive), ou de désintérêt complet (s''éloigne et refuse de revenir). La séance doit également s''arrêter si la récompense est offerte trop rapidement sans effort, ou si le chien devient trop excité.', 'Observer attentivement les réactions du chien face au puzzle. Noter s''il montre de la curiosité, de l''engagement, de la frustration, ou de l''indifférence. Suivre sa progression dans la recherche et l''extraction des récompenses au fil des séances.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/puzzle-expert.png'),
('puzzle-facile-senior', 'Le ''Puzzle Facile'' est un excellent exercice pour stimuler mentalement votre chien et lui apprendre à résoudre des problèmes simples. Il utilise des jouets interactifs ou des objets du quotidien pour cacher des friandises, encourageant ainsi le chien à réfléchir pour obtenir sa récompense. Cet exercice développe la patience, la concentration et renforce votre lien avec votre compagnon.', NULL, NULL, 'Puzzle facile', 'Stimulation mentale douce', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement les friandises dans le puzzle, fait preuve de persévérance et réussit à obtenir la majorité des friandises cachées sur une session donnée.', 'Le chien montre des signes de fatigue, de frustration excessive, ou a extrait toutes les friandises du puzzle.', 'Observer si le chien manipule le jouet activement et réussit à extraire au moins une friandise pendant la session.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/puzzle-facile-senior.png'),
('puzzle-intermediaire', 'Le puzzle intermédiaire est un jeu de stimulation mentale qui demande à votre chien de trouver des récompenses cachées en manipulant divers mécanismes. Cet exercice développe la résolution de problèmes et la patience canine. Il est idéal pour les chiens qui aiment fouiller et chercher.', NULL, NULL, 'Puzzle intermédiaire', 'Puzzle avec mécanismes multiples', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien réussit à obtenir la majorité des friandises cachées, manipulant activement différents mécanismes du puzzle. Il montre une attitude positive et engageante envers l''activité.', 'Le chien montre des signes évidents de stress, de frustration excessive, ou d''épuisement. Le puzzle est cassé ou détruit. Le chien a complètement perdu intérêt et ne s''engage plus dans l''activité.', 'Observez si le chien utilise ses pattes et son museau pour interagir avec le puzzle. Vérifiez s''il fait preuve de curiosité et de persévérance. Notez s''il mange les récompenses une fois qu''il les a obtenues.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/puzzle-intermediaire.png'),
('ramasser-objet', 'Cet exercice apprend à votre chien à rapporter un objet que vous lui lancez ou que vous lui désignez. C''est une excellente façon de stimuler mentalement et physiquement votre compagnon, et elle renforce votre lien. Commencez avec des objets faciles à attraper et augmentez progressivement la difficulté.', NULL, NULL, 'Ramasser un objet', 'Prendre et rapporter un objet désigné', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien prend l''objet sans hésitation, le rapporte directement au propriétaire et le lâche dans sa main ou à ses pieds à la demande. L''exercice est répété plusieurs fois avec succès.', 'Le chien montre des signes de fatigue, de stress ou de frustration (halètement excessif, bâillements, évitement de l''objet). Si le chien mordille l''objet pendant un long moment sans l''attraper ou le rapporter.', 'Observer si le chien prend volontairement l''objet désigné, le rapporte au propriétaire et le lâche sur commande, dans un environnement calme et sans distraction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ramasser-objet.png'),
('ranger-jouets', 'Apprenez à votre chien à ranger ses jouets dans une panière désignée. Cet exercice renforce le lien avec votre chien tout en lui apprenant une tâche utile et divertissante. Il encourage la patience et le contrôle de soi, tout en réduisant le désordre à la maison.', NULL, NULL, 'Ranger ses jouets', 'Mettre les jouets dans un panier', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien dépose correctement 8 fois sur 10 le jouet dans la panière lorsqu''il est invité, et ce, dans différents contextes.', 'Le chien montre des signes de frustration, d''anxiété, ou une désaffection marquée pour l''exercice ou le jouet, ou s''il est épuisé.', 'Observer le chien ramasser un jouet désigné, le transporter jusqu''à la panière et le déposer à l''intérieur à la demande.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ranger-jouets.png'),
('rappel-progressif-distance', 'Le rappel à distance croissante est un exercice essentiel pour assurer la sécurité de votre chien en promenade. Il consiste à appeler votre chien depuis une distance de plus en plus grande, récompensant ainsi systématiquement son retour. Cet exercice renforce le lien de confiance entre vous et votre chien, tout en garantissant qu''il vous obéira même en présence de distractions.', NULL, NULL, 'Rappel à distance croissante', 'Augmenter progressivement la distance', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et avec enthousiasme à chaque appel, quelle que soit la distance (jusqu''à la limite raisonnable maîtrisée) et le niveau de distraction, sans hésitation.', 'Le chien montre de la peur, de l''évitement, ou une détresse visible lors de l''exercice ; le chien est systématiquement distrait et indifférent à l''appel ; ou si l''exercice devient frustrant pour le duo.', 'Vérifier la réactivité du chien à l''appel verbal sur différentes distances et dans des environnements avec des niveaux de distraction variés, en observant la rapidité et l''enthousiasme de son retour.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-progressif-distance.png'),
('rappel-sifflet', 'Le rappel au sifflet est une technique essentielle pour assurer la sécurité de votre chien et le ramener à vous rapidement dans diverses situations. Cet exercice enseigne au chien à associer un son spécifique, celui du sifflet, à l''action de revenir vers vous. Il est particulièrement utile dans les environnements où le chien peut être distrait ou potentiellement en danger.', NULL, NULL, 'Rappel au sifflet', 'Associer un coup de sifflet au retour', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et joyeusement vers le propriétaire dès qu''il entend le sifflet, même en présence de distractions modérées.', 'Le chien montre des signes de stress, de peur, de fatigue excessive, ou ignore systématiquement le sifflet malgré des tentatives répétées de renforcement. Si le chien est récompensé de manière incohérente ou si l''environnement devient dangereux.', 'Pour valider l''exercice, le chien doit revenir vers le propriétaire en réponse au signal du sifflet dans au moins 80% des essais, quelle que soit la distraction présente dans un environnement sûr et contrôlé.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-sifflet.png'),
('rappel-distractions', 'Le rappel avec distractions est un exercice essentiel pour assurer la sécurité de votre chien et renforcer votre lien. Il apprend à votre chien à ignorer les éléments perturbateurs et à revenir vers vous quoi qu''il arrive. C''est la base d''une communication efficace et d''une relation de confiance.', NULL, NULL, 'Rappel avec distractions', 'Revenir malgré les distractions', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et joyeusement à chaque appel, ignorant les distractions présentes, et s''arrête bien à mon niveau pour recevoir sa récompense, même dans des environnements variés avec un niveau de distraction significatif.', 'Si le chien montre des signes de stress, de peur, ou refuse catégoriquement de revenir malgré les encouragements et les récompenses. Il faut alors simplifier l''exercice, le rendre moins long, ou simplement arrêter pour une autre fois.', 'Effectuer 5 rappels réussis sur 6 dans un environnement avec 3 distractions différentes, d''une difficulté croissante. Le chien ne doit pas avoir hésité plus de 3 secondes avant de démarrer son retour.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-distractions.png'),
('rappel-position', 'Cet exercice vise à renforcer le rappel de votre chien, en lui apprenant à revenir vers vous et à s''asseoir juste devant vous. C''est une étape cruciale pour un rappel fiable et un contrôle accru dans diverses situations. Le chien apprend à anticiper votre demande et à adopter une position de respect et d''attention. La durée de 8 minutes permet de travailler de manière ciblée sans épuiser le chien. Préparez-vous à féliciter et récompenser chaque effort.', NULL, NULL, 'Rappel avec position finale', 'Revenir et s''asseoir devant', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement à l''appel et s''assoit devant vous, en maintenant le contact visuel pendant quelques secondes, de manière répétée.', 'Le chien montre des signes de stress, de fatigueExcessive (bâillements fréquents, halètement excessif, tentatives de fuite), ou devient très distractible et ne répond plus aux commandes.', '3 succès sur 5 essais consécutifs à une distance donnée et avec distractions légères.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-position.png'),
('rappel-cache', 'Le rappel caché est un exercice avancé qui enseigne au chien à chercher son propriétaire lorsque celui-ci est caché. Cela renforce le lien et la confiance entre le chien et son maître, tout en stimulant l''instinct de recherche du chien. C''est un excellent moyen de pratiquer le rappel dans un environnement contrôlé et amusant.', NULL, NULL, 'Rappel caché', 'Revenir quand le maître se cache', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien trouve son propriétaire dans un délai raisonnable (variable selon la difficulté) avec enthousiasme et un comportement joyeux, puis accepte la récompense sans hésitation.', 'Le chien montre des signes de stress, de peur, de frustration excessive, ou est physiquement épuisé. Si l''apprentissage stagne malgré plusieurs tentatives et ajustements.', 'Le chien doit activement chercher son propriétaire dès que le complice lâche la laisse et que l''appel est lancé. Il doit se diriger dans la direction générale de la cachette.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-cache.png'),
('rappel-urgence', 'Le rappel d''urgence est une commande essentielle pour la sécurité de votre chien. Il permet de le rappeler à vous immédiatement, même s''il est distrait par un autre chien, une odeur ou un bruit. Cet exercice nécessite une pratique régulière pour être efficace dans toutes les situations.', NULL, NULL, 'Rappel d''urgence', 'Signal d''urgence pour retour immédiat', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien doit s''arrêter immédiatement ce qu''il fait, se tourner vers le handler et courir à sa rencontre dès qu''il entend la commande ''Viens !'' (ou le nom suivi de ''Viens !''), et ce, dans 90% des cas sur 10 tentatives dans un environnement moyennement distrayant.', 'Arrêter l''exercice si le chien montre des signes de stress excessif, de peur, ou d''agressivité. Si le chien ne progresse pas du tout après plusieurs séances, revoir la méthode d''entraînement, la valeur des récompenses, ou consulter un professionnel.', 'Le protocole de validation consiste à vérifier que le chien revient systématiquement à l''appel ''Viens !'' dans des environnements variés, avec et sans distraction, et ce, même s''il est engagé dans une activité.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-urgence.png'),
('rappel-base', 'L''exercice ''Rappel de base'' apprend à votre chien à revenir vers vous quand vous l''appelez. C''est un ordre fondamental pour la sécurité et le contrôle, essentiel au quotidien. Une pratique régulière dans différents environnements renforcera la fiabilité du rappel.', NULL, NULL, 'Rappel de base', 'Revenir quand on appelle son nom', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien revient vers le maître en moins de 5 secondes après l''appel, même avec des distractions légères, et montre un langage corporel joyeux à son arrivée.', 'Le chien montre des signes de stress, d''anxiété ou de peur, ou ignore systématiquement l''ordre malgré des récompenses adaptées.', 'Start in a low-distraction environment (e.g., home). Call the dog from 5 meters away. Repeat 5 times. Progress to a fenced yard. Call the dog from 10 meters away, with mild distractions (e.g., toy on the ground). Repeat 5 times. Finally, practice in a safe, open area with more significant distractions (e.g., other dogs at a distance, people walking by) from 15 meters. Repeat 5 times.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/rappel-base/tutorial-sheet.png'),
('rappel-nuit', 'Le rappel de nuit est un exercice crucial pour assurer la sécurité de votre chien lorsqu''il est dehors dans l''obscurité. Il permet à votre chien de revenir vers vous rapidement à l''appel, même avec des distractions visuelles et auditives réduites. Pratiquer cet exercice régulièrement renforce la confiance et la réactivité de votre chien.', NULL, NULL, 'Rappel de nuit', 'Revenir dans l''obscurité', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient systématiquement et avec enthousiasme à l''appel, indépendamment de la distance (dans la limite du raisonnable) et des légères distractions nocturnes, lorsqu''il est tenu en laisse ou avec une longe.', 'Le chien montre des signes de peur, d''anxiété, un refus complet de coopérer, ou le rappel devient dangereux en raison de distractions majeures ou d''un environnement non sécurisé.', 'Demander au chien de revenir de différentes distances et dans des environnements légèrement plus sombres et avec des distractions discrètes (ex: bruits lointains). Le chien doit répondre à 80% des demandes dans les 5 secondes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-nuit.png'),
('rappel-course', 'Le rappel en course est un exercice avancé qui enseigne au chien à revenir vers son maître même en situation de distraction ou de mouvement. Il est essentiel pour garantir la sécurité du chien et renforcer le lien entre le propriétaire et l''animal. Cet exercice demande de la patience, de la constance et une bonne compréhension des signaux canins.', NULL, NULL, 'Rappel en course', 'Revenir en pleine course', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient au premier appel, sans hésitation, même en présence de distractions modérées (autres chiens à distance, personnes qui bougent). Il s''arrête calmement devant le maître ou s''assoit selon l''instruction.', 'Le chien montre des signes de stress, de fatigue excessive, ou devient complètement indifférent aux appels malgré un effort constant. Si l''exercice devient frustrant pour le chien ou le maître, il est préférable de s''arrêter et de revenir à une étape plus facile.', 'Vérifier la réactivité du chien à l''appel lors de différentes activités (course, marche, jeu) et dans divers environnements. L''objectif est que le chien abandonne toute distraction pour revenir immédiatement et joyeusement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-course.png'),
('rappel-jeu', 'Le rappel en jeu est une excellente méthode pour renforcer le lien avec votre chien tout en lui apprenant à revenir vers vous, même en présence de distractions. Cet exercice utilise le jeu comme récompense principale, rendant l''apprentissage amusant et motivant. Il est particulièrement efficace pour les chiots et les chiens ayant une grande envie de jouer, transformant une commande essentielle en un moment de complicité.', NULL, NULL, 'Rappel en jeu', 'Interrompre le jeu pour revenir', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et joyeusement à chaque appel, indépendamment de la présence de son jouet préféré à proximité, et s''arrête de façon à pouvoir être récompensé par le jeu.', 'Le chien montre des signes de stress, d''épuisement, d''agression envers le jouet ou l''humain, ou refuse catégoriquement de participer ou de revenir malgré des encouragements répétés et des ajustements.', 'Effectuer 5 rappels réussis consécutifs dans un environnement contrôlé (peu de distractions), puis introduire 3 rappels réussis dans un environnement avec de légères distractions, et enfin 2 rappels réussis dans un environnement modérément distrayant.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-jeu.png'),
('rappel-libre', 'Le rappel en liberté complète est l''un des commandements les plus importants pour la sécurité de votre chien et votre tranquillité d''esprit. Il consiste à faire revenir votre chien vers vous lorsqu''il est détaché de toute contrainte. Cet exercice renforce votre lien et assure que votre chien peut être rappelé même dans des environnements très stimulants.', NULL, NULL, 'Rappel en liberté complète', 'Rappel sans longe en terrain ouvert', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et joyeusement à votre appel, sans hésitation, dans au moins 80% des répétitions dans un environnement donné, même avec des distractions présentes. Il doit s''arrêter volontairement à vos pieds ou à l''endroit désigné.', 'Le chien montre des signes de stress, de peur, ou de fatigue excessive. Le jeu devient une contrainte plutôt qu''un plaisir. Les rappels commencent à échouer systématiquement, indiquant qu''il faut revenir à des étapes plus faciles ou faire une pause. Si le nombre de succès chute drastiquement dans un environnement donné.', 'Répétez l''exercice dans différents environnements de plus en plus distrayants, en commençant par des environnements calmes et fermés et en progressant vers des lieux publics (parcs, forêts) pendant les heures creuses. Chaque journée d''entraînement doit inclure un rappel réussi dans l''environnement actuel avant de passer au suivant.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-libre.png'),
('rappel-longe', 'Le rappel en longe est un exercice fondamental pour assurer la sécurité de votre chien en public et renforcer votre lien. Il permet à votre chien d''apprendre à revenir vers vous lorsqu''il est appelé, même s''il est distrait par son environnement. Cet exercice est particulièrement utile pour les chiens encore jeunes ou ceux qui ont tendance à fuguer ou être trop indépendants.', NULL, NULL, 'Rappel en longe', 'Rappel sécurisé avec longe de 10m', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient systématiquement vers le maître dès le premier appel, quelle que soit la distance (dans la limite de la longe), et sans hésitation.', 'Le chien répond de manière aléatoire, ou s''il tire constamment sur la longe en essayant de s''échapper au lieu de venir vers le maître. Si le chien montre des signes de stress ou de peur.', 'Tester le rappel en longe dans un environnement contrôlé, puis progressivement dans des environnements avec plus de distractions. Augmenter la distance. Utiliser la longe pour assurer le succès et la sécurité, mais toujours dans le but de laisser l''autonomie au chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-longe.png'),
('rappel-avec-chiens', 'Cet exercice vise à enseigner à votre chien à revenir vers vous malgré la présence d''autres congénères, un défi courant pour de nombreux propriétaires. Il est crucial pour la sécurité de votre chien et pour maintenir une bonne relation avec les autres propriétaires de chiens. Une approche progressive et positive est essentielle pour garantir le succès et le bien-être de votre animal.', NULL, NULL, 'Rappel en présence de chiens', 'Revenir quand d''autres chiens sont présents', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et volontairement à chaque commande de rappel, quelle que soit la présence d''un autre chien, et s''arrête calmement à côté du propriétaire ou à ses pieds, en attendant la récompense ou la prochaine instruction.', 'Le chien montre des signes de stress importants (halètements excessifs, queue basse, oreilles en arrière, tentative de fuite), une agressivité envers le propriétaire ou l''autre chien, ou si la session crée une frustration ou une peur notable chez le chien, arrêt immédiat et retour à des étapes plus simples.', 'Pendant les exercices, observer systématiquement si le chien tourne la tête vers le propriétaire à la première commande de rappel et s''il maintient son regard et sa direction vers le propriétaire jusqu''à son arrivée, même en présence d''un autre chien à une distance définie au préalable.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-avec-chiens.png'),
('rappel-entre-2-personnes', 'Le rappel entre deux personnes est un exercice ludique et efficace pour renforcer l''obéissance de votre chien, particulièrement dans des environnements avec distractions. Il apprend au chien à revenir rapidement vers vous ou une autre personne désignée, même lorsque d''autres stimulis sont présents. Cet exercice améliore la connexion entre le chien et son propriétaire tout en développant sa concentration.', NULL, NULL, 'Rappel entre 2 personnes', 'Ping-pong entre deux humains', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient rapidement et joyeusement vers la personne qui l''appelle, même en présence de distractions modérées, et accepte la récompense. La distance entre les deux personnes peut être élargie jusqu''à 15-20 mètres.', 'Le chien montre des signes de stress, de fatigue excessive, de peur, ou refuse de participer. Si les erreurs deviennent fréquentes, il faut réduire la difficulté et reprendre l''exercice.', 'L''exercice est répété 10 fois dans un environnement calme. Le chien doit se déplacer vers la personne qui l''appelle à chaque essai, sans hésitation excessive. La laisse est détendue ou détachée la plupart du temps.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-entre-2-personnes.png'),
('rappel-gibier', 'Le rappel face au gibier est un exercice avancé de contrôle et d''obéissance, essentiel pour les chiens ayant une forte pulsion de prédation. Il consiste à rappeler votre chien alors qu''il est distrait par une source de gibier potentielle. Cet exercice demande patience, cohérence et une bonne compréhension du comportement de votre chien pour assurer sa sécurité et celle de la faune.', NULL, NULL, 'Rappel face au gibier', 'Revenir malgré la présence de gibier', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se détourne activement de la distraction de gibier pour revenir au handler, sans avoir besoin d''une traction sur la longe, et accepte la récompense. Le taux de réussite doit être supérieur à 80% dans des conditions maîtrisées.', 'Arrêtez l''exercice si le chien est constamment en état de stress, s''il échoue systématiquement malgré les ajustements, ou si la sécurité est compromise (risque de fuite, danger pour le gibier ou le chien). Reprenez un entraînement plus simple.', 'L''exercice est validé lorsque le chien est capable de rompre le contact visuel avec une distraction de gibier (sans poursuite) pour revenir vers le propriétaire, même s''il montre initialement un intérêt. Le rappel doit être rapide et volontaire, avec une récompense appropriée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-gibier.png'),
('rappel-reward-jackpot', 'Le rappel jackpot est un exercice avancé visant à renforcer l''attention de votre chien en lui offrant une récompense exceptionnelle lorsqu''il revient vers vous. Il consiste à rendre la venue de votre chien extrêmement gratifiante, transformant ainsi le rappel en un événement très attendu et positif. Cet exercice est particulièrement utile pour les chiens ayant des distractions importantes ou un rappel peu fiable.', NULL, NULL, 'Rappel jackpot', 'Rappels récompensés avec haute valeur aléatoire', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien revient volontairement et rapidement à la première commande, quelle que soit la distance (dans les limites raisonnables), sans hésitation, et s''arrête devant le handler pour être récompensé. La réactivité et l''enthousiasme du chien sont constants.', 'Le chien montre des signes de stress, d''épuisement, de frustration (ex: ignorer les récompenses, mordiller, fuir). Si le chien ne parvient pas à réaliser l''exercice même avec une réduction significative des distractions et une augmentation des récompenses, il est préférable de faire une pause et de consulter un professionnel.', 'Observer que le chien anticipe et exécute le rappel avec enthousiasme, même en présence de distractions modérées. Le chien doit venir directement vers le handler dès l''appel, ou après une brève pause pour identifier la source sonore.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-reward-jackpot.png'),
('rappel-pendant-repas', 'Le rappel pendant l''exploration est un exercice essentiel pour renforcer la relation de confiance entre le chien et son maître, tout en lui permettant de découvrir son environnement en toute sécurité. Il apprend au chien à revenir vers son propriétaire même lorsqu''il est distrait par des odeurs et des stimuli extérieurs. Cet exercice est fondamental pour garantir la sécurité du chien dans des environnements non clôturés.', NULL, NULL, 'Rappel pendant exploration', 'Interrompre un reniflage pour revenir', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et avec enthousiasme dès qu''il entend l''ordre de rappel, même en présence de stimuli forts tels que d''autres chiens ou des animaux sauvages (dans un environnement sécurisé).', 'Arrêtez l''exercice si le chien montre des signes de stress, d''anxiété, de fatigue excessive, ou si vous observez une baisse significative de motivation. Reprenez plus tard, éventuellement à une phase plus simple.', 'S''assurer que le chien répond au rappel dans au moins 80% des essais dans des conditions de distraction modérées, tout en maintenant un comportement joyeux à l''arrivée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-pendant-repas.png'),
('rappel-sans-friandise', 'Le rappel sans friandise est un exercice essentiel qui renforce le lien entre le propriétaire et son chien, en utilisant exclusivement le renforcement positif verbal et social. Il permet au chien d''associer le rappel à des interactions agréables avec son maître, plutôt qu''à une récompense matérielle. Cet entraînement est crucial pour la sécurité du chien dans diverses situations.', NULL, NULL, 'Rappel sans friandise', 'Rappel fiable avec récompense sociale uniquement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se retourne immédiatement à l''appel vocal, se dirige rapidement et joyeusement vers le propriétaire, et arrive à son niveau pour une interaction positive, sans hésitation ni distraction. L''exercice doit être reproductible dans des environnements variés.', 'Le chien montre des signes de stress, de peur ou d''inconfort. L''exercice devient frustrant pour le chien ou le propriétaire. Des rappels constants sont nécessaires dans un environnement où le chien devrait être naturellement plus libre.', 'Effectuez l''exercice dans plusieurs environnements avec des niveaux de distraction croissants. Assurez-vous que le chien répond à l''appel dans au moins 80% des tentatives.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-sans-friandise.png'),
('rappel-sous-pression', 'Le rappel sous pression opérationnelle est un exercice avancé visant à entraîner votre chien à revenir à vous même dans des situations de stress, de distraction ou de danger simulé. Cet entraînement renforce la confiance et la fiabilité de votre partenaire canin, le rendant plus apte à répondre à vos appels en toutes circonstances. Il est crucial pour les chiens de travail, les chiens de sauvetage, et tout propriétaire souhaitant un chien extrêmement réactif.', NULL, NULL, 'Rappel sous pression opération', 'Revenir malgré la stimulation intense', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien rompt instantanément sa distraction et revient promptement vers le maître à la commande, même en présence de stimuli intenses et pertinents.', 'Le chien montre des signes de stress excessif, de peur panique, ou si des erreurs répétées indiquent un manque de préparation des phases précédentes. Arrêter également si la sécurité du chien ou des personnes est compromise.', 'Observer le chien réagir à la commande de rappel dans des environnements de plus en plus distrayants, en simulant des scénarios de pression opérationnelle contrôlée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-sous-pression.png'),
('rappel-terrain-varie', 'Le rappel sur terrain varié est un exercice essentiel pour assurer la sécurité de votre chien dans divers environnements. Il consiste à appeler votre chien, quelle que soit la présence de distractions naturelles (herbe, feuilles, petites bosses). Cet entraînement renforce le lien entre vous et votre chien tout en lui apprenant à rester concentré et réceptif à votre appel.', NULL, NULL, 'Rappel terrain varié', 'Rappel sur différents terrains', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien répond au rappel dans 90% des cas, allant spontanément et rapidement vers le propriétaire, quel que soit le terrain (herbe, feuilles, sable, gravier) et en présence de distractions naturelles modérées, dans différentes situations.', 'Le chien montre des signes de stress excessif, d''épuisement, ou se montre déficient à répondre même dans des conditions faciles. Un manque de progression sur plusieurs séances malgré des ajustements représente également un critère d''arrêt pour réévaluer la méthode.', 'Pendant chaque séance d''entraînement, enregistrez le nombre de fois où le chien répond au rappel dès le premier appel. Notez également la qualité de sa réponse (rapidité, enthousiasme) et le niveau de distraction présent.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-terrain-varie.png'),
('rappel-tres-longue-distance', 'Le rappel à très longue distance est un exercice avancé qui apprend à votre chien à revenir vers vous même lorsqu''il est distrait et à une distance considérable. L''objectif est de construire une confiance solide et un lien indestructible entre vous et votre compagnon. Cet exercice demande de la patience, de la cohérence et une progression graduelle pour garantir le succès et la sécurité de votre chien.', NULL, NULL, 'Rappel très longue distance', 'Rappel à 200m+ en terrain accidenté', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement (moins de 5 secondes d''hésitation) et avec enthousiasme à l''appel sur 200 mètres dans un environnement semi-occupé, même en présence d''autres chiens ou personnes, en utilisant une voix claire et une action de récompense immédiate à l''arrivée.', 'Le chien montre des signes de détresse, de peur, d''épuisement ou de frustration répétée. Si le chien ignore systématiquement l''appel malgré des ajustements, il est préférable d''arrêter pour éviter de compromettre le lien et la motivation.', 'Effectuer le rappel sur des distances de 50m, 100m, puis 200m dans un environnement contrôlé avec distractions légères. Le succès doit être mesuré par une interaction positive et une récompense offerte au chien à chaque fois.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-tres-longue-distance.png'),
('rappel-vocal-varie', 'Le rappel vocal varié est un exercice essentiel pour assurer la sécurité de votre chien. Il consiste à lui apprendre à revenir vers vous rapidement lorsque vous l''appelez, en utilisant différentes clés vocales. Cet exercice renforce le lien entre le propriétaire et le chien et permet une bonne gestion des situations imprévues.', NULL, NULL, 'Rappel vocal varié', 'Répondre à différents tons de voix', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien revient immédiatement et de manière fiable à chaque appel, quelle que soit la distance ou le niveau de distraction, en cherchant activement le handler et en s''arrêtant à ses pieds ou lorsqu''il est invité à le faire.', 'Le chien montre des signes de stress, de peur ou de fatigue. L''exercice devient frustrant pour le chien ou le handler. Le chien ne montre aucune amélioration malgré des ajustements dans la méthode.', 'Commencer dans un environnement clos et sans distraction. S''assurer que le chien répond à 80% des appels sur 10 essais consécutifs avant de passer à l''étape suivante ou d''augmenter la difficulté. Se déplacer dans des environnements de plus en plus distrayants et tester le rappel à différentes distances.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rappel-vocal-varie.png'),
('rapport-eau', 'Le rapport à l''eau est un excellent exercice pour familiariser votre chien avec l''eau tout en renforçant son rappel et sa confiance. Il s''agit d''apprendre au chien à aller chercher un objet flottant dans l''eau et à vous le rapporter. Cet exercice est particulièrement bénéfique pour les chiens qui ont une affinité naturelle pour l''eau ou que vous souhaitez encourager à aimer nager.', NULL, NULL, 'Rapport à l''eau', 'Rapporter un objet dans l''eau', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien va chercher activement le jouet dans l''eau, le ramène et le donne au handler en échange d''une récompense, et ce, de manière répétée et autonome.', 'Signes de fatigue, de stress, d''irritation ou d''aversion marqué de la part du chien. Le chien refuse catégoriquement d''aller dans l''eau ou de rapporter le jouet malgré des tentatives positives.', 'Observer si le chien entre volontairement dans l''eau, récupère le jouet et le rapporte au propriétaire sans hésitation.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rapport-eau.png'),
('rapport-objet-ring', 'L''exercice du rapport d''objet, connu sous le nom de ''ring'', est une activité ludique et stimulante qui renforce le lien entre le chien et son propriétaire. Il consiste à apprendre au chien à rapporter volontairement un objet spécifique et à le céder calmement. Cette méthode encourage la concentration, l''obéissance et la confiance du chien.', NULL, NULL, 'Rapport d''objet (ring)', 'Rapporter l''objet du juge', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien prend l''objet rapidement, le rapporte directement au propriétaire, et le cède calmement sur demande, sans hésitation ni réticence, plusieurs fois de suite.', 'Le chien montre des signes de frustration, d''épuisement, ou perd l''intérêt pour l''exercice. Il mordille excessivement l''objet ou le propriétaire. L''exercice devient une lutte.', 'Observer si le chien prend volontairement l''objet, s''il revient vers le propriétaire et s''il cède l''objet sur commande. Répéter l''exercice plusieurs fois par séance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rapport-objet-ring.png'),
('gather-large', 'Cet exercice avancé est conçu pour entraîner votre chien à revenir à vous même lorsqu''il est distrait par un environnement stimulant ou un groupe d''autres chiens. Il simule une situation où le chien pourrait s''égarer ou s''éloigner de manière incontrôlée. L''objectif est de renforcer le rappel dans des conditions de forte distraction, en utilisant des signaux clairs et une approche progressive pour garantir le succès et la sécurité.', NULL, NULL, 'Rassemblement large champ', 'Rassembler un troupeau dispersé', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien interrompt son exploration ou son jeu et revient volontairement et rapidement vers le handler dès le premier appel, quel que soit le niveau de distraction.', 'Le chien montre des signes de stress, de peur, ou de fatigue excessive. Le handler commence à se sentir frustré ou en colère. Le chien est systématiquement incapable de répondre à l''appel malgré les ajustements.', '3 succès sur 5 essais dans la configuration de distraction actuelle avant de passer à un niveau de difficulté supérieur.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gather-large.png'),
('reactivite-portail', 'Cet exercice vise à gérer l''excitation de votre chien lorsqu''il entend quelqu''un sonner à la porte ou passer devant la maison. L''objectif est qu''il reste calme et ne réagisse pas de manière excessive, en canalisant son énergie vers une action appropriée. C''est une étape clé pour une cohabitation sereine, particulièrement utile pour les chiens un peu trop gardiens ou sensibles aux bruits extérieurs. Nous allons apprendre à votre compagnon à associer ces événements à un comportement attendu, plutôt qu''à une réaction impulsive.', NULL, NULL, 'Réactivité au portail', 'Calme quand quelqu''un sonne ou passe', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ne manifeste plus de réaction barking, ne court plus vers la porte, et reste dans sa zone désignée avec une attitude détendue pendant et après le bruit.', 'Le chien montre des signes de stress excessif (halètement, tremblements, bâillements fréquents, évitement du regard) malgré les ajustements, ou l''exercice devient une source de frustration pour le handler ou le chien.', '3 succès consécutifs sur 5 tentatives où le chien reste calme dans sa zone désignée dès le premier signal sonore.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-portail.png'),
('reactivite-bruit', 'Cet exercice vise à aider votre chien à mieux réagir face aux bruits soudains et imprévus. L''objectif est de transformer une réaction de peur ou d''excitation en une réponse plus calme et contrôlée. Nous apprendrons à votre chien à associer ces bruits à quelque chose de positif, comme une friandise, plutôt qu''à une source de stress. C''est une étape clé pour renforcer sa confiance et son équilibre émotionnel dans diverses situations du quotidien. Prévoyez des sessions courtes et régulières pour de meilleurs résultats.', NULL, NULL, 'Réactivité aux bruits soudains', 'Gérer les bruits inattendus', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde brièvement la source du bruit, puis se tourne vers vous ou reste calme, sans signe de peur, de fuite ou d''anxiété marquée.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, tentatives de fuite répétées), ou si vous êtes fatigué ou impatient.', 'Réussir 4 fois sur 5 essais consécutifs à un niveau sonore donné avant d''augmenter l''intensité ou de changer de type de bruit.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-bruit.png'),
('reactivite-velo', 'Cet exercice vise à aider votre chien à mieux réagir face aux cyclistes, une situation souvent stressante pour eux à cause de la vitesse et du mouvement soudain. L''objectif est de transformer cette rencontre en une expérience neutre, voire positive, en apprenant à votre chien à rester calme et concentré sur vous. Nous allons travailler sur la désensibilisation progressive et le renforcement des comportements calmes, en utilisant sous-seuil de réaction pour garantir le succès. Il s''agit d''améliorer la communication entre vous et votre chien dans des environnements stimulants.', NULL, NULL, 'Réactivité aux cyclistes', 'Rester calme face aux vélos', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste assis ou au pied calmement, sans tentative d''aboiement, de poursuite ou de traction sur la laisse, pendant le passage du cycliste et une minute après.', 'Le chien montre des signes de stress importants (halètement excessif, queue basse, tremblements, tentatives de fuite, vocalises).', '3 succès sur 5 essais avec des cyclistes passant à une distance raisonnable (ex: moins de 20 mètres).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-velo.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('reactivite-joggers', 'Cet exercice vise à désensibiliser votre chien à la présence de joggeurs, en lui apprenant à rester calme et concentré sur vous même lorsqu''une personne en tenue de sport passe en courant. Il s''adresse aux chiens qui ont déjà acquis les bases de l''obéissance et qui réagissent de manière modérée aux distractions comme les joggeurs. L''objectif est que votre chien apprenne à ignorer le joggeur pour rester attentif à vos indications, renforçant ainsi votre complicité et son autocontrôle.', NULL, NULL, 'Réactivité aux joggeurs', 'Ignorer les personnes qui courent', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne tire pas sur la laisse, n''aboie pas, et porte son attention sur vous ou regarde le joggeur sans réactivité excessive lorsque celui-ci passe devant vous.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, queue entre les pattes, tentatives de fuite), ou s''il devient ingérable malgré vos efforts. Arrêtez l''exercice si vous ou votre chien êtes frustrés ou anxieux.', '3 succès consécutifs sur 5 essais, où le chien ignore le joggeur ou se tourne vers le maître sans signe d''excitation excessive (halètement, tension), à une distance intermédiaire.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-joggers.png'),
('reactivite-voitures', 'Cet exercice aide votre chien à devenir plus calme et indifférent face aux voitures qui passent. L''objectif est que votre compagnon apprenne à détourner son attention des véhicules pour se concentrer sur vous. Nous allons travailler sur la gestion de l''environnement afin de créer des associations positives et réduire les réactions négatives. Cela améliorera grandement vos promenades en toute sérénité.', NULL, NULL, 'Réactivité aux voitures', 'Ignorer les véhicules en mouvement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde la voiture puis détourne son regard vers vous de manière autonome ou suite à une commande simple, sans signe de stress ni réaction. Il accepte la récompense proposée.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, tentative de fuite, grognements) ou une réactivité incontrôlable (aboiements, hurlements, tiraillements extrêmes).', '3 succès sur 5 essais consécutifs à la même distance et avec le même niveau de trafic.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-voitures.png'),
('reactivite-laisse', 'Cet exercice vise à aider votre chien à mieux gérer la frustration qu''il peut ressentir lorsque sa laisse l''empêche d''atteindre quelque chose d''intéressant, comme un autre chien, une personne ou une odeur. L''objectif est de lui apprendre à rester calme et concentré sur vous malgré ces tentations. Nous allons progressivement augmenter la difficulté tout en maintenant le succès pour renforcer sa confiance et sa compréhension.', NULL, NULL, 'Réactivité en laisse spécifiqu', 'Travailler la frustration de la laisse', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne tire pas sur la laisse, et maintient son attention sur vous ou répond à vos commandes, même en présence de la distraction.', 'Le chien montre des signes de stress importants (halètement excessif, bâillements répétés, oreilles en arrière, queue basse), de frustration intense (aboiements, sauts excessifs), ou si vous sentez que vous perdez le contrôle de la situation.', 'Effectuer 3 fois l''exercice avec succès dans des conditions similaires avant de considérer l''objectif atteint pour cette séance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reactivite-laisse.png'),
('rear-cross', 'Le ''Rear Cross'' est une manoeuvre avancée qui consiste à faire passer votre chien sous votre bras, derrière votre dos, pour finir du côté opposé. Cet exercice est excellent pour développer la coordination et la compréhension mutuelle entre vous et votre chien. Il permet d''améliorer la fluidité des mouvements et de préparer à des séquines plus complexes en agility ou en obéissance. Maîtriser ce mouvement demande de la patience et une bonne communication.', NULL, NULL, 'Rear cross', 'Changement de côté par l''arrière', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien passe sous le bras du handler, complète le cercle derrière le handler et se positionne correctement à droite de ce dernier, réactif aux commandes verbales et corporelles.', 'Signes de stress ou de fatigue chez le chien (bâillements répétés, halètement excessif, évitement marqué), ou frustration du handler.', '3 succès consécutifs sur 5 tentatives.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rear-cross.png'),
('recherche-eau-sauvetage', 'Cette activité avancée simule une situation de sauvetage aquatique. Le chien doit utiliser son flair pour localiser une personne perdue dans l''eau, même si elle est partiellement immergée ou cachée par des éléments naturels. L''exercice met l''accent sur la concentration du chien, sa confiance dans l''eau et sa capacité à travailler sous pression pour retrouver et signaler la victime.', NULL, NULL, 'Recherche aquatique de sauveta', 'Trouver une victime dans l''eau', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien localise la victime dans l''eau ou sur la rive, effectue un signal d''alerte clair et attend la récompense sans désobéissance.', 'Le chien montre des signes de fatigue excessive, de stress important, de peur ou d''agressivité. Le handler ne doit pas continuer si la sécurité du chien ou des autres est compromise.', 'Réussir 4 recherches sur 6 essais consécutifs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-eau-sauvetage.png'),
('recherche-objet-perdu', 'L''exercice ''Recherche d''objet perdu'' à un niveau intermédiaire permet de renforcer la complicité entre le maître et son chien tout en stimulant son flair. Le chien doit apprendre à chercher activement un objet spécifique qui lui est familier, appartenant à son maître. Cette activité ludique développe la concentration du chien et son aptitude à résoudre des problèmes simples, le tout dans une ambiance positive et motivante.', NULL, NULL, 'Recherche d''objet perdu', 'Retrouver un objet du maître', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie et manipule (prend dans la gueule ou renifle intensivement) l''objet désigné par le maître dans un délai raisonnable.', 'Signes de frustration, de fatigue, d''ennui ou de stress chez le chien (halètement excessif, bâillements répétés, évitement, queue basse).', '3 succès sur 5 essais consécutifs dans des conditions similaires.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-objet-perdu.png'),
('recherche-objets', 'Ce jeu de recherche avancé sollicite l''intelligence de votre chien et renforce votre complicité. L''objectif est de lui apprendre à identifier et à rapporter un objet spécifique parmi plusieurs, même s''il est caché ou moins évident à trouver. C''est un excellent moyen de stimuler mentalement votre compagnon tout en travaillant son rappel et son obéissance dans un contexte ludique et motivant.', NULL, NULL, 'Recherche d''objets', 'Trouver et rapporter des objets du maître', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie et rapporte l''objet spécifique demandé par le maître, même s''il est caché parmi d''autres objets, et ce, de manière autonome et joyeuse.', 'Le chien montre des signes de fatigue, de frustration (soupirs, salivations excessives, arrêts fréquents) ou de désintérêt persistant. Arrêtez toujours avant qu''il ne se lasse complètement.', '3 succès sur 5 essais consécutifs dans des conditions similaires.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-objets.png'),
('recherche-friandise-sol', 'La recherche de friandises au sol est une activité ludique et stimulante qui fait appel à l''odorat de votre chien. C''est un excellent moyen d''occuper son esprit et de le dépenser mentalement, surtout par mauvais temps.  Cet exercice renforce la confiance en soi de votre chien et son autonomie tout en apprenant à respecter une consigne simple.  Il est parfait pour développer sa concentration et sa patience, transformant une simple friandise en une véritable chasse au trésor.', NULL, NULL, 'Recherche de friandises au sol', 'Trouver des friandises cachées', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement dès la consigne, utilise son flair pour trouver les friandises cachées et montre de l''enthousiasme à chaque découverte.', 'Le chien montre des signes de fatigue (halètement excessif, perte d''intérêt), de frustration (pleurnichard, tentatives infructueuses répétées) ou si vous avez utilisé toutes les friandises prévues et que la séance doit se terminer.', '3 succès sur 5 essais pour valider le niveau actuel.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-friandise-sol.png'),
('recherche-jouet-cache', 'Ce jeu simple mais efficace permet à votre chien d''utiliser son flair naturel pour retrouver son jouet préféré. C''est une excellente activité pour stimuler mentalement votre compagnon et renforcer votre lien. En quelques étapes faciles, vous transformerez la recherche d''un objet en un jeu excitant et gratifiant pour votre chien, même s''il débute dans ce genre d''exercice.', NULL, NULL, 'Recherche de jouet caché', 'Retrouver son jouet préféré caché', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien montre de l''enthousiasme à l''idée de chercher, utilise activement son flair, et retrouve le jouet en moins d''une minute dans la plupart des cachettes.', 'Le chien montre des signes de stress, de frustration excessive, de fatigue évidente, ou s''il se désintéresse totalement même avec une motivation accrue.', 'Le chien doit réussir à retrouver le jouet dans 3 cachettes différentes sur 5 essais consécutifs lors de la séance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-jouet-cache.png'),
('recherche-personne', 'Le jeu de piste est une activité fantastique pour stimuler mentalement votre chien et renforcer votre complicité. Dans cet exercice intermédiaire, votre chien apprendra à utiliser son flair pour retrouver une personne qui s''est délibérément cachée. C''est un excellent moyen de canaliser son énergie et de développer sa confiance en lui, tout en s''amusant à l''extérieur.', NULL, NULL, 'Recherche de personne', 'Trouver une personne cachée', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien montre de l''intérêt pour l''odeur, suit la piste activement et trouve la personne cachée dans un délai raisonnable, en réagissant positivement à sa découverte.', 'Le chien montre des signes de stress, de peur ou de fatigue extrême. Le chien est complètement désintéressé par l''exercice après plusieurs tentatives. Le handler ne parvient pas à faire progresser le chien malgré les ajustements.', '3 succès sur 5 essais, où le chien trouve la personne cachée sans aide excessive du handler.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-personne.png'),
('recherche-personne-disparue', 'Cet exercice, « Recherche de personne disparue », est conçu pour les chiens ayant déjà une bonne expérience en pistage. D''une durée d''environ 30 minutes, il simule la recherche d''une personne qui s''est éloignée dans un environnement varié. Le chien devra faire preuve d''autonomie et de concentration pour suivre une piste humaine fraîche, même en présence de distractions. C''est un excellent moyen de renforcer le lien entre vous et votre chien tout en stimulant ses capacités olfactives et cognitives de manière ludique et exigeante.', NULL, NULL, 'Recherche de personne disparue', 'Suivre la piste d''un disparu', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien retrouve la personne cachée en moins de 15 minutes après avoir reçu l''indication olfactive, sans avoir besoin d''être constamment guidé.', 'Le chien montre des signes de stress excessif, de fatigue importante, ou si la météo devient dangereusement défavorable (canicule, orage violent).', '3 succès sur 5 essais', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-personne-disparue.png'),
('recherche-truffe', 'Cet exercice avancé simule une véritable recherche de truffes pour votre chien, développant son flair et sa concentration. Vous allez enterrer des friandises ou des jouets à l''odeur prononcée dans des endroits variés et un peu plus complexes. Le chien devra utiliser toutes ses capacités olfactives pour localiser ces récompenses cachées, renforçant ainsi sa confiance en lui et votre lien.', NULL, NULL, 'Recherche de truffes', 'Trouver des truffes enfouies', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien localise de manière autonome la récompense, la manipule ou la rapporte (selon ce qui est attendu) sans aide excessive de la part du maître.', 'Le chien montre des signes de fatigue évidente (halètement excessif, léthargie), de stress (bâillements répétés, oreilles en arrière) ou de frustration marquée.', 'Réussir 4 caches sur 6 essais, avec une difficulté variable.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-truffe.png'),
('recherche-vehicule-suspect', 'Cet exercice avancé demande à votre chien d''inspecter un véhicule stationné de manière autonome, en marquant sa découverte sans interagir avec le véhicule lui-même. Il est conçu pour tester la concentration, l''obéissance et la capacité de votre chien à ignorer les distractions environnementales fortes. L''objectif est de développer une méthode d''investigation sûre et efficace pour votre chien face à des objets potentiellement intéressants mais hors de portée.', NULL, NULL, 'Recherche de véhicule suspect', 'Inspecter un parking ou véhicule', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien inspecte le véhicule de manière autonome sur au moins 2 côtés, sans tentative de contact, d''interaction ou de montée, et revient calmement vers le maître sur commande.', 'Le chien montre des signes de stress excessif (halètements, tremblements, tentatives de fuite), s''il y a un risque de sécurité pour le chien ou l''environnement, ou si le chien devient incontrôlable malgré les tentatives de correction.', '3 succès consécutifs sur 5 contextes différents (différents véhicules, différents parkings, différentes heures de la journée).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-vehicule-suspect.png'),
('recherche-figurant', 'L''exercice ''Recherche du figurant'' est un jeu d''odorat stimulant où votre chien doit utiliser son flair pour retrouver une personne cachée. C''est une excellente activité pour renforcer votre complicité et canaliser l''énergie de votre chien, tout en développant sa confiance et son autonomie. Idéal pour les chiens qui aiment les défis olfactifs, cet exercice évolue facilement et peut se pratiquer dans différents environnements une fois les bases maîtrisées.', NULL, NULL, 'Recherche du figurant', 'Trouver le figurant caché', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien utilise son nez pour localiser activement le figurant caché, indépendamment des indications visuelles du handler, et exprime de la joie à la découverte.', 'Le chien montre des signes évidents de stress, de fatigue, ou perd complètement intérêt dans l''exercice pendant plusieurs essais.', 'Réussir 3 recherches consécutives avec moins d''aide du handler.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-figurant.png'),
('recherche-avalanche', 'La recherche en avalanche est une simulation avancée où votre chien doit localiser une personne cachée sous une épaisse couche de neige. Cet exercice renforce son instinct naturel de pistage et sa capacité à travailler de manière indépendante dans des conditions difficiles. La réussite dépend d''une communication claire et d''une confiance mutuelle, le chien apprenant à faire confiance à son flair pour ''lire'' le terrain et vous faire savoir qu''il a trouvé la ''victime''.', NULL, NULL, 'Recherche en avalanche', 'Trouver une victime sous la neige', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien localise la personne cachée sous la neige et l''indique clairement par un comportement approprié (grattage, aboiement, marquage dynamique) avant la fin du temps imparti. La récompense est acceptée avec enthousiasme.', 'Le chien montre des signes de fatigue excessive, de stress, ou d''une perte d''intérêt marquée. Si le temps imparti est dépassé sans trouver la personne. Si les conditions météorologiques deviennent dangereuses.', '3 succès consécutifs sur 5 tentatives validées par l''assistant et l''éducateur.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-avalanche.png'),
('recherche-decombres', 'Cet exercice simule une situation de recherche réelle où votre chien doit localiser une personne dissimulée sous un tas d''objets ressemblant à des décombres. Il s''agit d''une épreuve d''endurance mentale et olfactive, qui demande concentration et persévérance de la part de votre chien. Le but est de faire en sorte que votre chien utilise son flair exceptionnel pour trouver la personne cachée, qu''importe la complexité de l''environnement.', NULL, NULL, 'Recherche en décombres', 'Trouver une victime sous les décombres', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien localise la personne cachée dans les décombres et exécute son signal de découverte de manière fiable et rapide.', 'Le chien montre des signes de stress, de fatigue excessive, ou perd tout intérêt pour la recherche.', '4 succès sur 5 essais consécutifs dans des conditions variées.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-decombres.png'),
('recherche-foret-nuit', 'Cet exercice avancé consiste à faire évoluer votre chien dans un environnement forestier une fois la nuit tombée. L''objectif est de renforcer son flair et sa confiance en lui dans des conditions de faible luminosité, en exploitant ses capacités olfactives naturelles. C''est une excellente manière de stimuler mentalement votre chien tout en explorant un nouvel environnement de manière sécurisée. Assurez-vous d''être parfaitement équipé pour cette aventure nocturne.', NULL, NULL, 'Recherche en forêt de nuit', 'Recherche nocturne en milieu boisé', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement, utilise son nez de manière autonome, localise la récompense cachée et la rapporte ou la mange sur demande. Il reste sous contrôle du conducteur malgré les distractions nocturnes.', 'Signes de stress excessif chez le chien (halètement important, tremblements, détachement, léchage des babines excessif, queue basse), mordre ou grogner, blessure du chien ou du conducteur, perte de visibilité critique, conditions météorologiques extrêmes.', '3 succès consécutifs sur 5 essais pour chaque niveau de difficulté : Facile, Moyen, Difficile.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-foret-nuit.png'),
('recherche-surface', 'La recherche en surface est un jeu d''odorat passionnant où votre chien utilise son nez pour localiser une personne cachée à l''air libre. Cet exercice simule une situation réelle de recherche afin d''aiguiser les capacités naturelles de votre chien. Cela renforce également votre complicité en travaillant ensemble vers un objectif commun. C''est une excellente activité pour dépenser mentalement et physiquement votre compagnon.', NULL, NULL, 'Recherche en surface', 'Trouver une victime en surface', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien utilise son flair pour localiser activement et de manière autonome la personne cachée, puis la signale (par exemple, en aboyant ou en s''asseyant près d''elle) avant de recevoir sa récompense.', 'Signes de fatigue évidente chez le chien (halètement excessif non lié à l''effort, prostration), perte d''intérêt marquée, ou si le chien devient stressé ou anxieux.', '3 succès sur 5 essais consécutifs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-surface.png'),
('recherche-zone-large', 'Votre chien excellent dans les exercices de flair, entraînez-vous maintenant à localiser une odeur cible dans un espace beaucoup plus grand. Le but est de lui apprendre à explorer une zone étendue de manière systématique, sans rien manquer. Cet exercice renforce sa concentration et sa capacité à isoler une odeur spécifique malgré les nombreuses distractions potentielles.', NULL, NULL, 'Recherche en zone large', 'Couvrir une large zone systématiquement', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien parcourt la zone de manière systématique et retrouve l''odeur cible sans aide excessive de votre part. Il montre de l''enthousiasme et de la concentration.', 'Signes manifestes de fatigue (halètements excessifs, ralentissement marqué), désintérêt total, stress (bâillements répétés, léchage des babines), ou si le chien montre des signes de douleur physique.', '3 succès sur 5 essais dans la même zone avec des caches différentes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recherche-zone-large.png'),
('recompenser-sommeil', 'Cet exercice simple et efficace vous aide à encourager votre chien à se détendre et à trouver le calme. En associant des moments de repos paisible à une récompense positive, vous renforcez l''idée que rester tranquille est bénéfique. C''est une excellente façon d''améliorer la relation avec votre compagnon tout en lui apprenant à gérer son énergie. Applicable dès le plus jeune âge, cet exercice peut transformer les moments de nervosité en instants de sérénité.', NULL, NULL, 'Récompenser le repos', 'Friandise quand le chien dort calmement', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Le chien s''installe paisiblement et reste détendu pendant plusieurs minutes, accepting les récompenses sans se lever ou s''agiter.', 'Le chien montre des signes de fatigue ou d''ennui visible, commence à s''agiter, cherche à interagir, ou si vous sentez que la session devient stressante pour lui.', '3 succès sur 5 essais consécutifs sur une période d''observation de 10 minutes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/recompenser-sommeil.png'),
('noms-personnes', 'Cet exercice simple et ludique permet à votre chien de renforcer son lien avec chaque membre de la famille. En associant des noms à des personnes spécifiques, votre chien développe sa compréhension de son environnement social et apprend à réagir de manière appropriée à chaque individu. C''est une excellente activité pour des chiens de tous âges, renforçant leur confiance et leur obéissance de manière positive. Commencez dès aujourd''hui pour un chien plus communicatif et mieux intégré à la famille !', NULL, NULL, 'Reconnaître les personnes', 'Associer les noms aux membres de la famille', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien répond à l''appel de chaque membre de la famille en se dirigeant vers eux de manière proactive et joyeuse, attendant la récompense.', 'Le chien montre des signes de fatigue, de stress (halètement excessif, bâillements répétés, évitement du regard) ou perd tout intérêt pour l''exercice.', '3 succès sur 5 essais pour chaque membre de la famille, où le chien se dirige spontanément et avec enthousiasme vers la bonne personne lors de son appel.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/noms-personnes.png'),
('reculer-pente', 'Cet exercice avancé, ''Reculer en Pente'', apprend à votre chien à reculer en douceur et avec confiance sur un terrain en pente. Cela renforce sa proprioception, son équilibre et sa confiance sur des surfaces irrégulières ou inclinées. C''est un excellent exercice pour les chiens qui évoluent dans des environnements variés ou qui pratiquent des sports canins nécessitant de l''agilité et du contrôle sur différents terrains. La communication entre vous et votre chien devient encore plus subtile.', NULL, NULL, 'Reculer en pente', 'Marche arrière sur terrain en pente', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien recule sur la pente demandée avec assurance, sans hésitation, en gardant son équilibre et en répondant à la commande vocale.', 'Signes de stress, de peur, de déséquilibre marqué, ou si le chien devient récalcitrant malgré des adaptations.', '3 succès sur 5 essais consécutifs sur une pente modérée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reculer-pente.png'),
('reculer-echelle', 'Le recul sur une échelle est un exercice d''agilité et de confiance avancé. Il demande au chien de se déplacer en arrière sur des barreaux d''échelle posés au sol, développant ainsi sa proprioception et sa coordination. Cet exercice renforce la communication entre le chien et son propriétaire, tout en lui apprenant à gérer des surfaces inhabituelles avec assurance.', NULL, NULL, 'Reculer sur une échelle', 'Marcher en arrière sur les barreaux', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien recule sur l''échelle sur demande, de manière fluide, sans hésitation ni perte d''équilibre, et en restant concentré sur le handler.', 'Signes de stress (bâillements excessifs, lèchements de babines répétés, queue basse), refus catégorique de coopérer, ou tout signe de douleur.', '3 succès consécutifs sur 5 essais pour chaque longueur de recul demandée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reculer-echelle.png'),
('refus-appat', 'Cet exercice avancé, le ''Refus d''appât'', vise à renforcer le contrôle de votre chien face aux tentations au sol. Il est essentiel pour sa sécurité et pour vous assurer qu''il ne ingérera rien de dangereux lors de vos promenades. L''objectif est d''apprendre au chien à ignorer complètement la nourriture (ou tout autre objet tentant) placée au sol, même lorsqu''il est seul avec elle, sur commande vocale ou visuelle. C''est une étape cruciale pour bâtir une relation de confiance et de communication solide entre vous et votre compagnon canin.', NULL, NULL, 'Refus d''appât', 'Ignorer la nourriture au sol', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore la friandise au sol sur commande verbale ou visuelle, même en présence de distractions légères, et revient au pied sans chercher à attraper l''appât.', 'Signes de stress, d''épuisement, de frustration excessive chez le chien, ou si le chien devient complètement focalisé sur la friandise et ignore toute tentative de redirection.', '3 succès sur 5 essais dans des conditions similaires avant de passer à une difficulté supérieure.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/refus-appat.png'),
('regarde-moi', 'L''exercice ''Regarde-moi'' est fondamental pour établir une bonne communication avec votre chien. Il permet de capter son attention en toutes circonstances et de renforcer le lien qui vous unit. C''est la base pour l''apprentissage de tout autre comportement, car un chien qui vous regarde est un chien qui est prêt à écouter et à apprendre. La clé est de rendre cet exercice positif et gratifiant pour lui.', NULL, NULL, 'Regarde-moi', 'Capter et maintenir le contact visuel', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien établit un contact visuel franc et soutenu (au moins 3 secondes) à la commande vocale ou à l''invitation, sans distraction.', 'Le chien montre des signes de stress (bâillements répétés, léchage des babines, queue basse) ou de fatigue. Arrêtez l''exercice si vous ou le chien êtes frustrés.', 'Effectuer 10 essais sur une journée. Le protocole est validé si le chien réussit 7 fois sur 10.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/97cef4a7-2b19-4b4b-9d17-6dcd1718cbe1.png'),
('relaxation-apres-crise', 'Cet exercice est conçu pour aider votre chien à retrouver son calme après un moment d''excitation, comme après une séance de jeu intense ou une interaction avec un autre chien. Il s''agit d''une routine simple mais efficace pour réapprendre à votre compagnon à se détendre sur commande. L''objectif est de construire une association positive entre le signal de relaxation et le retour au calme, indispensable pour un chien équilibré et bien dans ses pattes.', NULL, NULL, 'Relaxation post-déclenchement', 'Routine de retour au calme', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se détend visiblement (soupirs, bâillements, corps relâché) dans les 10 secondes suivant le signal de calme, et accepte la récompense. Il est ensuite capable de rester dans cet état pendant au moins 1 minute.', 'Le chien montre des signes de stress prononcé (halètement excessif, tremblements, tentative de fuite), devient hyperactif malgré les efforts, ou montre des signes d''ennui profond et de désintérêt. Fatigue visible du chien ou du maître.', '3 succès sur 5 essais consécutifs dans l''environnement d''apprentissage.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/relaxation-apres-crise.png'),
('relaxation-progressive', 'La relaxation progressive est une méthode douce pour apprendre à votre chien à gérer son stress et à se détendre. En relâchant méthodiquement les tensions musculaires, chien par chien, on lui apprend à passer d''un état d''alerte à un état de calme profond. Ce protocole s''effectue sur 15 jours, intensifiant progressivement la durée et la profondeur de la relaxation pour un résultat durable.', NULL, NULL, 'Relaxation progressive de Karr', 'Protocole en 15 jours', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien se couche volontairement, ferme les yeux, ralentit sa respiration et ne montre aucun signe de tension musculaire lors des massages.', 'Signes de stress marqués (oreilles en arrière, queue basse, bâillements répétés, halètement excessif), grognements, tentative de fuite échappée.', '3 succès sur 5 essais consécutifs dans l''environnement d''apprentissage.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/relaxation-progressive.png'),
('tapis-chauffant', 'Cet exercice vise à apprendre à votre chien à se détendre et à trouver le calme sur un tapis chauffant. C''est une excellente méthode pour l''aider à se relaxer, particulièrement lors des journées froides ou pour les chiens sensibles au froid. L''objectif est qu''il associe le tapis chauffant à un endroit de repos sécurisant et confortable, lui permettant de lâcher prise et de se déconnecter du stress extérieur. Une relaxation sur tapis chauffant peut être bénéfique pour les chiens plus âgés ou ceux ayant des problèmes articulaires.', NULL, NULL, 'Relaxation tapis chauffant', 'Repos sur surface chauffée', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien monte sur le tapis chauffant de manière autonome, s''y allonge et adopte une posture de relaxation (corps détendu, respiration calme).', 'Signes de stress ou d''inconfort du chien (halètement excessif, bâillements répétés sans être fatigué, tentatives de fuite), température du tapis jugée trop chaude ou trop froide.', '3 succès sur 5 essais consécutifs, où le chien reste volontairement sur le tapis pendant au moins 2 minutes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/tapis-chauffant.png'),
('rencontre-chat', 'Cette séance prépare votre chiot à un contact positif et contrôlé avec un chat. L''objectif est d''établir une première impression sereine pour les deux animaux, en favorisant le calme et la curiosité mutuelle. Nous allons utiliser des règles simples et un environnement sécurisé pour construire une base de confiance solide. Le bien-être de votre chiot et du chat est notre priorité absolue.', NULL, NULL, 'Rencontre chat-chiot', 'Première rencontre avec un chat', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chiot reste calme, ne montre pas de comportement de prédation ou d''excitation excessive. Le chat n''affiche pas de peur ou d''agressivité et reste détendu ou curieux.', 'Le chiot aboie, mordille l''air, tourne en rond, ou montre des signes d''anxiété. Le chat feule, hérisse le poil, aplatit les oreilles, tente de fuir de manière répétée ou agressive.', '3 succès consécutifs sur 5 essais, où les deux animaux montrent un comportement calme et curieux sans signe de stress.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rencontre-chat.png'),
('rencontre-humains', 'Cet exercice permet à votre chien de s''habituer à croiser des personnes calmes dans la rue. L''idée est d''apprendre au chien à rester tranquille et à ne pas réagir de manière excessive lorsqu''il voit un inconnu. L''objectif est de construire des expériences positives pour votre compagnon, afin qu''il associe les rencontres avec des humains à des moments de calme et de bonheur. C''est une étape essentielle pour un chien bien équilibré dans la vie de tous les jours.', NULL, NULL, 'Rencontre d''humains calmes', 'Approcher des inconnus sans stress', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien observe l''humain sans réagir (pas d''aboiement, pas de tiraillement, pas de tension), reste à côté de son handler et apprécie la friandise offerte pour le calme.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, oreilles en arrière, queue entre les pattes, grognements). Si le chien est trop agité ou focalisé sur l''humain au point de ne plus être réceptif aux récompenses.', '3 succès sur 5 essais consécutifs lors de la même séance, avec différents inconnus et dans des environnements variés.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rencontre-humains.png'),
('rencontre-chien-calme', 'Cet exercice vise à enseigner à votre chien une approche respectueuse et contrôlée lors de la rencontre avec un autre chien inconnu, mais réputé calme et équilibré. Il s''agit de favoriser une interaction positive et sécuritaire, en apprenant à votre chien à lire les signaux de l''autre individu et à rester dans un état émotionnel calme. L''objectif est de gérer les excitations potentielles et de construire la confiance de votre chien face à de nouvelles rencontres.', NULL, NULL, 'Rencontre de chien calme', 'Approche contrôlée d''un chien équilibré', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste attentif à sonHandler malgré la présence de l''autre chien, ne tire pas sur la laisse, n''aboie pas et montre des signes de détente.', 'Le chien montre des signes de stress importants (halètement excessive, queue basse, oreilles en arrière, tentatives répétées de fuite), si l''autre chien devient trop envahissant ou stressant, ou si le Handler se sent dépassé.', '3 succès sur 5 essais consécutifs, démontrant un comportement calme et une bonne gestion de la laisse.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/rencontre-chien-calme.png'),
('renoncement-friandise', 'Cet exercice simple mais essentiel enseigne à votre chien la maîtrise de soi et la patience face à une tentation. Il apprend à ignorer une friandise alléchante placée devant lui, renforçant ainsi votre lien et sa capacité à se concentrer sur vous. C''est une excellente base pour des commandes plus complexes et un outil précieux pour gérer les distractions dans la vie de tous les jours.', NULL, NULL, 'Renoncement à la friandise', 'Laisser la friandise posée sans la prendre', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien attend calmement que vous lui annonciez verbalement qu''il peut soit prendre une autre friandise, soit que l''exercice est terminé, sans jamais toucher la friandise posée au sol.', 'Le chien montre des signes de frustration excessive (halètement fort, gémissements, tentatives répétées de mordre ou d''attraper la friandise au sol malgré vos interventions) ou semble anxieux.', '3 succès sur 5 essais consécutifs dans des conditions similaires.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/renoncement-friandise.png'),
('reponse-au-nom', 'Cet exercice simple mais fondamental aide votre chien à associer son nom à une attention positive. L''objectif est que votre chien tourne systématiquement la tête vers vous dès qu''il entend son nom. C''est la première étape pour établir une communication claire et un rappel fiable. En rendant cet exercice amusant et gratifiant, vous renforcez votre lien tout en construisant une base solide pour des apprentissages futurs. Commencez dans un environnement calme pour optimiser la concentration de votre compagnon.', NULL, NULL, 'Réponse au nom', 'Tourner la tête systématiquement à l''appel', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien tourne la tête et établit un contact visuel avec le propriétaire dès qu''il entend son nom, dans 80% des cas dans un environnement familier et calme.', 'Le chien montre des signes évidents de stress (bâillements excessifs, léchage des babines, oreilles en arrière, queue basse), de fatigue, ou s''il refuse de coopérer. Le chien est frustré ou a perdu son intérêt.', '3 succès sur 5 appels consécutifs dans des conditions similaires (même environnement, même niveau de distraction)', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reponse-au-nom.png'),
('resilience-bruits-chiot', 'Cet exercice vise à aider votre chiot à devenir plus confiant face aux bruits du quotidien. En l''exposant de manière positive et progressive à divers sons, vous construisez sa résilience et évitez qu''il ne développe des peurs. L''objectif est de créer des associations positives, transformant les bruits potentiellement effrayants en éléments neutres ou même agréables. C''est une étape cruciale pour un chien bien équilibré et serein.', NULL, NULL, 'Résilience aux bruits (chiot)', 'Habituation précoce aux sons', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chiot regarde le son, puis se reconcentre sur vous ou continue son activité sans signe de stress (oreilles en arrière, queue basse, halètement excessif, tentatives de fuite). Il accepte les friandises.', 'Le chiot montre des signes évidents de peur (tremblements, halètement excessif, tentative de fuite, vocalises d''alerte). Si l''exercice devient une source de stress répétée pour le chiot.', '3 succès consécutifs sur 5 essais pour un niveau sonore et une distance donnés.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/resilience-bruits-chiot.png'),
('resilience-echec', 'Cet exercice aide votre chien à comprendre qu''il ne peut pas toujours avoir ce qu''il veut, tout en restant calme et serein. Nous allons utiliser une récompense alléchante, mais inaccessible immédiatement, pour enseigner la patience. L''objectif est de développer sa résilience émotionnelle, c''est-à-dire sa capacité à gérer la frustration sans développer de comportements indésirables comme l''agitation ou les miaulements. C''est une étape clé pour un chien équilibré et confiant, capable de faire face aux petites déceptions du quotidien.', NULL, NULL, 'Résilience face à l''échec', 'Accepter de ne pas obtenir ce qu''on veut', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien montre des signes de détente (bâillements, détourne la tête, s''assoit ou s''allonge calmement) et attend patiemment la friandise après que le poing soit fermé.', 'Le chien montre des signes de stress excessif (halètement intense, tremblements, tentatives répétées et violentes de prendre la friandise malgré les efforts) ou une perte totale d''intérêt pour la friandise.', 'Réussir 3 fois sur 5 essais consécutifs, où le chien se calme avant de recevoir la friandise.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/resilience-echec.png'),
('resistance-distractions-pro', 'Cet exercice avancé pousse la concentration de votre chien à son paroxysme. Le but est de lui apprendre à ignorer volontairement des distractions importantes tout en maintenant une connexion avec vous. Nous allons créer un environnement contrôlé mais stimulant pour tester et renforcer sa capacité à rester concentré sur vos consignes, même lorsque le monde extérieur l''appelle. C''est l''étape ultime pour un chien fiable dans toutes les situations.', NULL, NULL, 'Résistance aux distractions (p', 'Rester concentré malgré le chaos', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien conserve sa posture ou revient vers le maître malgré une distraction significative (ex: jouet qui tombe, autre personne qui passe à proximité, bruit soudain) pendant une durée acceptable (minimum 10 secondes pour un ''reste'', retour immédiat pour un ''viens'').', 'Signes de stress excessif chez le chien (halètement prononcé, bâillements répétés, queue basse, tentatives de fuite), réactivité incontrôlable, refus catégorique d''obéir. Si le chien devient irritable ou anxieux.', 'Valider lorsque le chien accomplit l''exercice demandé (ex: ''Reste'') dans 4 cas sur 5 essais, malgré la présence d''une distraction établie.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/resistance-distractions-pro.png'),
('respiration-guidee', 'Cet exercice simple mais efficace permet au propriétaire de mieux comprendre et gérer le stress de son chien. En apprenant à synchroniser sa propre respiration avec celle de son chien, le maître devient un guide apaisant. Cela renforce le lien et aide le chien à se sentir plus en sécurité, en reproduisant un rythme calme que le chien peut imiter. C''est un outil précieux pour gérer les situations stressantes du quotidien.', NULL, NULL, 'Respiration guidée', 'Le maître inspire/expire pour calmer le chien', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, sa respiration ralentit et devient plus profonde, il se détend physiquement (relâche les muscles, bâille, ferme les yeux).', 'Le chien montre des signes clairs de stress (halètement excessif, tremblements, tentatives d''évasion), il est distrait malgré vos efforts, ou vous sentez que le chien ne bénéficie plus de l''exercice.', '3 succès sur 5 essais consécutifs lors de différentes séances.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/respiration-guidee.png'),
('reste-distractions', 'Cet exercice de niveau avancé est conçu pour renforcer la commande ''Reste'' de votre chien, même en présence de distractions significatives. L''objectif est que votre chien conserve sa position couchée ou assise pendant que vous introduisez des éléments qui pourraient normalement le faire bouger. Cela demande de la confiance mutuelle et une excellente communication entre vous et votre chien, prouvant ainsi sa capacité à gérer son excitation et à rester concentré sur vous.', NULL, NULL, 'Reste avec distractions', 'Maintenir le reste malgré stimuli', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile dans la position demandée (assis ou couché) malgré la présence et l''activité des distractions introduites, jusqu''à la commande de libération.', 'Le chien montre des signes de stress excessif (halètement prononcé, tremblements, bâillements répétés), ou s''il essaie de s''échapper de manière répétée malgré les tentatives de le canaliser.', 'Valider l''exercice avec 3 succès sur 5 essais où le chien a maintenu le ''Reste'' pendant l''intégralité de la durée de la distraction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reste-distractions.png'),
('reste-assis', 'Cet exercice est essentiel pour apprendre à votre chien à maîtriser l''immobilité. Il pose les bases de nombreux autres apprentissages en renforçant son auto-contrôle. Commence par de courtes périodes pour garantir le succès et construire la confiance mutuelle. Le but est que votre chien reste calme et immobile quand vous le lui demandez, même avec quelques distractions.', NULL, NULL, 'Reste en position assise', 'Maintenir la position assise avec durée croissante', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient la position assise pendant le temps imparti (quelques secondes à 1 minute selon le progrès), sans se lever, sans bouger inutilement, jusqu''à la commande de libération.', 'Le chien montre des signes de stress, d''ennui profond (bâillements excessifs, léchage des babines répété), ou que l''exercice devient frustrant pour l''un ou l''autre. Finir toujours sur une note positive.', '3 succès sur 5 essais consécutifs sur la durée et la distance demandées.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/0c7887e1-3148-4b4a-964a-356caae87e85.png'),
('reste-couche', 'Apprenez à votre chien à rester immobile dans la position couchée, même lorsque vous vous éloignez. Cet exercice simple mais fondamental renforce la confiance et le contrôle mutuels. Commencez par de courtes durées et augmentez progressivement le temps pour bâtir la patience de votre compagnon sur quatre pattes. C''est la base pour des exercices plus complexes comme le ''Au rappel'' ou le ''Pas bouger''.', NULL, NULL, 'Reste en position couchée', 'Maintenir le couché avec durée croissante', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste couché et immobile pendant la durée demandée, même lorsque vous vous éloignez et revenez.', 'Le chien montre des signes évidents de stress, d''agitation ou de douleur. Ou si vous n''arrivez pas à obtenir un succès clair après plusieurs essais.', '3 succès sur 5 essais à une distance et durée définies.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/192b6117-adaa-46b9-b221-c5e3a336fc0d.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('reveil-defense', 'Cet exercice avancé vise à enseigner à votre chien une réaction défensive contrôlée lorsqu''il est surpris au repos. Il apprendra à se défendre calmement et efficacement face à une menace simulée, renforçant ainsi sa confiance et votre lien. La clé est de le surprendre légèrement, puis de récompenser sa réaction appropriée, en veillant toujours à sa sécurité et à son bien-être émotionnel. Cet entraînement est réservé aux chiens ayant déjà une bonne base d''obéissance et de confiance.', NULL, NULL, 'Réveil et défense', 'Réaction défensive depuis le repos', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien réagit à la surprise par une posture d''alerte ou une légère mise en garde verbale contrôlée, puis accepte la récompense et le relâchement sans agressivité ni crainte.', 'Le chien montre des signes de stress importants (halètement excessif non lié à l''effort, léchage des babines, oreilles basses, queue entre les pattes, tentative de fuite) ou une agressivité incontrôlée.', '3 succès sur 5 essais, sans réaction excessive ou de panique.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/reveil-defense.png'),
('ritual-depart', 'Ce rituel vise à rendre vos départs habituels et sans émotion pour votre chien, réduisant ainsi son anxiété ou son excitation. L''idée est de distinguer clairement le moment où vous vous préparez à partir de celui où vous partez réellement. En pratiquant cela régulièrement, votre chien apprendra à rester calme et détaché, quelle que soit l''occasion.', NULL, NULL, 'Rituel de départ neutre', 'Banaliser les départs', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne montre pas de signes d''excitation ou d''anxiété (léchage de babines excessif, bâillements de stress, respiration haletante, tentatives de suivre ou de se mettre devant la porte) lorsque vous effectuez le rituel de départ.', 'Le chien montre des signes clairs de détresse ou d''excitation incontrôlable, rendant la pratique contre-productive.', '3 succès consécutifs sur 5 essais pour chaque étape clé (avant la pause, après la pause, départ effectif).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ritual-depart.png'),
('ritual-retour', 'Ce rituel vise à transformer les retours à la maison, souvent source d''excitation pour le chien, en un moment de calme et de contrôle. L''objectif est que votre chien comprenne que votre retour ne signifie pas forcément une explosion de joie immédiate, mais un retour à une routine paisible. En pratiquant cet exercice régulièrement, vous apprendrez à votre chien à gérer son excitation et à attendre patiemment votre entrée dans la maison. Cela renforcera votre complicité et posera les bases d''un comportement plus serein au quotidien.', NULL, NULL, 'Rituel de retour calme', 'Banaliser les retours', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, assis ou couché, et ne saute pas, n''aboie pas ou ne tourne pas en rond de manière excessive dès votre entrée et pendant les premières minutes.', 'Le chien montre des signes de stress excessif, d''agressivité ou est totalement incapable de se calmer malgré vos efforts répétés.', '3 succès sur 5 essais consécutifs sans incident majeur.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ritual-retour.png'),
('roule', 'Le tour ''Roule'' est un trick impressionnant qui demande de la coordination et de la confiance. Il s''agit de faire rouler votre chien sur le dos, complète. Cet exercice intermédiaire enrichit le lien avec votre chien tout en stimulant son intelligence et son corps. Assurez-vous que votre chien maîtrise déjà le ''Couché'' et le ''Donne la patte'' avant de vous lancer dans cette aventure.', NULL, NULL, 'Roule', 'Faire une roulade complète', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien effectue une roulade complète sur son dos en suivant la commande vocale et/ou le guidage gestuel, de manière fluide et sans hésitation.', 'Le chien montre des signes de fatigue, de stress (bâillements excessifs, halètements, évitement du regard), ou devient frustré.', '3 succès sur 5 essais consécutifs, sans aide physique.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/roule.png'),
('calme-fin-journee', 'La routine du soir est un moment privilégié pour apaiser votre chien avant qu''il ne dorme. Elle vous permet de renforcer votre lien tout en l''aidant à se détendre après une journée bien remplie. Cette courte séance de 10 minutes est conçue pour être douce et agréable pour vous deux, créant une transition calme vers la nuit.', NULL, NULL, 'Routine du soir', 'Séquence de détente avant le coucher', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, accepte les caresses sans protester, son corps se détend (soupirs, bâillements, paupières mi-closes), et il s''installe tranquillement pour dormir à la fin.', 'Le chien montre des signes de stress évidents (redressement, oreilles en arrière, tentative de fuite répétée), s''il s''endort complètement et ne souhaite plus d''interaction, ou si vous constatez qu''il est trop agité pour bénéficier de l''exercice.', '3 succès consécutifs sur 5 essais', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-fin-journee.png'),
('salut', 'Cet exercice, connu sous le nom de ''Salute'' ou ''Arc-en-ciel'', est excellent pour améliorer la flexibilité et la conscience corporelle de votre chien. Il consiste à demander au chien de baisser l''avant de son corps tout en gardant l''arrière surélevé, comme s''il vous saluait avec respect. C''est un mouvement qui sollicite des muscles souvent moins utilisés et qui a un effet relaxant pour le chien une fois bien maîtrisé.', NULL, NULL, 'Salut', 'Baisser l''avant du corps', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien baisse spontanément l''avant de son corps (poitrail et tête) en gardant ses quatre pattes au sol et ses hanches surélevées, à la réception de la commande vocale ''Salut''.', 'Le chien montre des signes de stress, de fatigue, d''inconfort (bâillements excessifs, halètement, tentatives de fuite) ou de frustration (grognements, mordillements). Si le chien n''y arrive vraiment pas après plusieurs tentatives, il vaut mieux arrêter et réessayer plus tard.', '3 succès consécutifs sur 5 essais dans un environnement calme.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/salut.png'),
('pneu-saut', 'Le saut dans le pneu est un exercice ludique qui renforce la confiance de votre chien et améliore son agilité. Il s''agit de faire passer votre chien à travers un cerceau ou un pneu suspendu à une hauteur adaptée à sa taille. Cet exercice demande de la coordination et de la compréhension mutuelle entre vous et votre compagnon canin, tout en s''assurant de sa sécurité et de son plaisir.', NULL, NULL, 'Saut dans le pneu', 'Sauter à travers un pneu suspendu', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit le pneu de manière autonome et enthousiaste lorsqu''il reçoit la commande vocale, sans hésitation ni besoin excessif de guidage.', 'Signs de stress, de peur ou de fatigue chez le chien; blessure; perte d''intérêt marquée du chien pour l''exercice.', '3 succès consécutifs sur 5 essais demandés.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pneu-saut.png'),
('saut-haies', 'Cet exercice d''agilité est conçu pour renforcer la confiance et la coordination de votre chien. Il s''agit de franchir des obstacles de différentes hauteurs, ce qui permet d''adapter le défi à ses capacités. C''est une excellente activité qui stimule le corps et l''esprit de votre compagnon tout en consolidant votre complicité. Nous allons travailler sur un parcours de haies progressif pour assurer la sécurité et le plaisir du chien.', NULL, NULL, 'Saut de haies', 'Sauter des haies de hauteur variable', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit la haie choisie avec aisance, sans hésitation, en gardant une posture coordonnée et en restant attentif aux consignes.', 'Signes de fatigue excessive, d''appréhension croissante, de douleur, ou si le chien devient frustré ou désintéressé par l''exercice.', '3 sauts réussis sur 5 tentatives consécutives à une étape donnée avant d''augmenter la difficulté.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/saut-haies.png'),
('saut-ponton', 'Cet exercice avancé est idéal pour les chiens qui aiment l''eau et qui sont à l''aise avec les hauteurs. Il s''agit d''apprendre au chien à sauter dans l''eau depuis un ponton ou une plateforme spécialement aménagée. C''est une excellente façon de renforcer la confiance de votre chien, son agilité et son plaisir dans un environnement aquatique contrôlé et sécurisé. Assurez-vous que la plateforme est stable et que l''eau est suffisamment profonde et sans danger.', NULL, NULL, 'Saut depuis un ponton', 'Sauter dans l''eau depuis une plateforme', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien saute de manière volontaire et confiante dans l''eau depuis le ponton pour attraper une friandise ou un jouet, sans signe de peur ou d''hésitation.', 'Le chien montre des signes de peur intense, d''anxiété, ou refuse catégoriquement de coopérer après plusieurs tentatives positives. Signes de fatigue ou d''hypothermie.', '3 succès sur 5 essais consécutifs pour chaque étape de progression.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/saut-ponton.png'),
('saut-longueur', 'Ce jeu stimule l''agilité et la confiance de votre chien. Il apprendra à évaluer une distance et à la franchir avec assurance. C''est un excellent moyen de renforcer votre complicité tout en dépensant son énergie de manière positive. Adaptez la distance à la taille et aux capacités de votre compagnon pour un apprentissage en toute sécurité.', NULL, NULL, 'Saut en longueur', 'Sauter une distance au sol', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit la distance demandée de manière fluide, sans appréhension, et revient éventuellement chercher sa récompense.', 'Signes de fatigue, d''anxiété, de peur chez le chien, ou refus répété d''exécuter l''exercice malgré les ajustements.', 'Effectuer 5 tentatives. Le chien doit franchir la distance sans hésitation majeure lors de 4 des 5 tentatives.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/saut-longueur.png'),
('sauter-bras', ' Cet exercice avancé apprend à votre chien à sauter avec agilité et contrôle dans vos bras tendus. C''est une démonstration de confiance mutuelle et d''une belle complicité, qui peut être amusante et impressionnante lors de l''entraînement.  Il nécessite une excellente communication et un lien fort entre vous et votre compagnon canin.', NULL, NULL, 'Sauter dans les bras', 'Sauter dans les bras du maître', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien saute de manière volontaire et contrôlée dans les bras du maître lorsque la commande est donnée.', 'Le chien montre des signes de fatigue, de stress, de peur, ou perd l''intérêt pour l''exercice. Si le chien se blesse ou refuse catégoriquement de coopérer.', '3 succès consécutifs sur 5 tentatives dans des conditions similaires.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('cerceau', 'Cet exercice amusant et simple permet d''apprendre à votre chien à passer à travers un cerceau tenu. C''est une excellente activité pour renforcer votre lien, améliorer la confiance de votre chien et lui apprendre à suivre vos indications avec enthousiasme. Commencez doucement et récompensez chaque petit succès pour rendre l''apprentissage positif et agréable pour vous deux.', NULL, NULL, 'Sauter dans un cerceau', 'Passer à travers un cerceau tenu', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien passe à travers le cerceau sans hésitation sur commande vocale et avec une tenue de laisse lâche.', 'Le chien montre des signes de stress, de fatigue ou de peur du cerceau ; ou si vous n''obtenez aucun progrès pendant plusieurs répétitions.', '3 succès consécutifs sur 5 essais à la hauteur demandée.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('sauter-obstacle', 'Préparez votre chien à franchir un obstacle de manière sécuritaire et amusante. Ce jeu développe la confiance et l''agilité de votre compagnon. Nous allons commencer progressivement pour que votre chien comprenne bien l''exercice. L''objectif est qu''il apprenne à sauter par-dessus une petite barre sans hésitation.', NULL, NULL, 'Sauter un obstacle', 'Franchir une barre en sautant', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit l''obstacle en sautant par-dessus sans hésitation, avec une prise d''élan adéquate, et sans toucher la barre.', 'Le chien montre des signes de fatigue évidente (halètement excessif, lenteur), de stress ou de peur (queue basse, oreilles en arrière, tentatives de fuite). Arrêter si le chien refuse catégoriquement de coopérer malgré les encouragements et les adaptations.', '3 sauts réussis sur 5 tentatives à la hauteur finale travaillée.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('sauts-ring', 'Cet exercice vise à perfectionner le franchissement d''obstacles de type "ring" pour les chiens avancés. Nous allons travailler la haie, la palissade et le fossé, en associant vitesse et précision. L''objectif est que le chien anticipe et franchisse ces obstacles en toute confiance et en toute sécurité, sous la conduite de son maître. C''est un excellent exercice pour renforcer la complicité et le contrôle, particulièrement utile dans les sports canins.', NULL, NULL, 'Sauts de ring', 'Haie, palissade, fossé', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit tous les types d''obstacles (haie, palissade, fossé) avec assurance, rapidité et sans hésitation, en suivant les indications du maître, et ce, sur plusieurs répétitions dans la séance.', 'Signes de fatigue évidente du chien, boiterie, crispation, peur, ou refus catégorique et répété de franchir un obstacle malgré les adaptations.', '3 succès consécutifs sur 5 essais pour chaque type d''obstacle et en combinaison.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('scenario-complet', 'Ce scénario avancé simule une situation réaliste où le chien doit réagir à une intrusion inattendue tout en maintenant le contrôle. L''objectif est d''évaluer la capacité du chien à rester calme et obéissant face à une distraction potentiellement stressante. Cet exercice renforce la confiance et la coopération entre le chien et son handler dans des contextes imprévus. Il est conçu pour les chiens ayant déjà une bonne maîtrise des bases de la protection.', NULL, NULL, 'Scénario complet de protection', 'Enchaînement réaliste complet', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien reste à mes côtés, calme et attentif, malgré la surprise. Il répond aux commandes ''Assis'', ''Reste'' ou ''Au pied'' rapidement et sans hésitation quand le complice est présent et se retire.', 'Le chien montre des signes de peur extrême (tremblements, tentatives de fuite répétées), une agressivité incontrôlée ou une absence totale de réaction aux commandes malgré plusieurs tentatives.', '3 succès sur 5 essais, avec une réaction maîtrisée à chaque fois.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('serviette-roulee', 'Cet exercice ludique permet à votre chien de développer ses capacités de résolution de problèmes et d''utiliser son flair. En lui apprenant à dérouler une serviette pour accéder à des récompenses cachées, vous stimulez son intellect tout en renforçant votre complicité. C''est une excellente activité pour les jours où les sorties sont limitées ou pour offrir un défi mental amusant à votre compagnon.', NULL, NULL, 'Serviette roulée', 'Dérouler une serviette pour trouver les friandises', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien arrive à défaire la serviette autonomeent pour accéder aux friandises.', 'Le chien montre des signes de fatigue, de frustration excessive, ou perd tout intérêt pour le jeu.', '3 succès sur 5 essais.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('shed', 'Cet exercice, appelé ''Shed'' ou ''Séparer'', est conçu pour entraîner vos chiens à rester calmes et obéissants lorsqu''ils sont séparés temporairement de leur groupe ou de leur propriétaire. C''est une étape cruciale pour renforcer la confiance et l''autonomie de chaque individu. Que vous ayez un seul chien ou plusieurs, apprendre à les gérer individuellement en présence d''autres renforce leur compréhension des règles et leur capacité à gérer la frustration ou l''excitation.', NULL, NULL, 'Shed (séparer)', 'Séparer un ou plusieurs animaux du groupe', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et dans la zone désignée pendant la durée demandée, sans montrer de signes de stress ou d''urgence à rejoindre le groupe.', 'Le chien montre des signes de stress importants, il n''arrive pas à rester dans la zone malgré les ajustements, ou il aboie de manière excessive et incontrôlée.', '3 succès sur 5 essais consécutifs pour chaque niveau de difficulté augmenté.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('auto-apaisement', 'Ce court exercice vise à vous aider à observer et à renforcer les moments où votre chien se sent détendu et en sécurité. En apprenant à identifier les signaux d''auto-apaisement, vous pourrez mieux comprendre ses émotions et l''aider à se calmer lorsqu''il est stressé ou excité. C''est une base essentielle pour construire une relation de confiance et de compréhension mutuelle avec votre compagnon.', NULL, NULL, 'Signaux d''auto-apaisement', 'Reconnaître et encourager le calme', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien montre de manière autonome au moins 3 signaux d''auto-apaisement différents dans un environnement calme.', 'Le chien montre des signes d''inconfort, d''anxiété, ou cherche à s''éloigner de manière répétée.', 'Observer 5 signaux d''auto-apaisement distincts sur 5 essais.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('signal-silencieux-pro', 'Cet exercice avancé de communication non verbale vise à renforcer la connexion entre vous et votre chien en utilisant exclusivement des gestes pour donner des ordres. L''objectif principal est que votre chien réagisse à vos signaux corporels, créant ainsi une compréhension mutuelle silencieuse et efficace. Cela démontre un niveau de dressage élevé et peut être particulièrement utile dans des environnements bruyants ou lorsque vous avez besoin de discrétion. Préparez-vous à aiguiser votre langage corporel et à observer attentivement les réactions de votre compagnon.', NULL, NULL, 'Signaux silencieux opérationne', 'Commander par gestes uniquement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute correctement la commande demandée uniquement par un geste, sans aide vocale ni aide de la laisse, avec un minimum de répétitions du geste.', 'Le chien montre des signes de stress (halètement excessif, bâillements, léchage des babines répété), de fatigue (perte d''intérêt, s''assoit spontanément) ou devient frustré (aboie, tourne en rond).', 'Réussir 4 commandes successives dans un environnement contrôlé, demandées sans aucun autre indice (visuel ou auditif).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('simulation-catastrophe', 'Cet exercice avancé simule un environnement chaotique et imprévisible pour tester la fiabilité des apprentissages de votre chien dans des conditions stressantes. L''objectif est de travailler le rappel inconditionnel, la gestion de l''environnement et le calme malgré le tumulte. Il s''agit d''un entraînement réaliste pour préparer votre chien à réagir calmement et obéir en toutes circonstances, même les plus extrêmes.', NULL, NULL, 'Simulation de catastrophe', 'Exercice complet en conditions réelles', 'La constance est la clé du succès', '60 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore la majorité des distractions, répond au rappel même en cas de forte perturbation, et conserve une attitude calme et attentive envers son handler.', 'Signes de détresse intense et prolongée chez le chien (halètement excessif, tremblements, tentatives de fuite désespérées, agressivité défensive).', '3 succès sur 5 essais pour chaque commande vocale et scénario de simulation.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('examen-veterinaire', 'Cet exercice simule une visite chez le vétérinaire pour habituer votre chien à être manipulé. L''objectif est de reproduire les gestes d''un examen corporel en toute sécurité et sans stress pour le chien. Cela inclut la palpation, l''observation des yeux, des oreilles, et une vérification rapide de la gueule. Une bonne préparation permet de prévenir l''anxiété lors des vraies consultations vétérinaires.', NULL, NULL, 'Simulation examen vétérinaire', 'Reproduire les gestes du vétérinaire', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et coopère durant les manipulations simulées sans montrer de signes de peur ou d''agressivité excessive, et tolère une brève ouverture de gueule. La manipulation est appréciée avec des friandises et des félicitations.', 'Le chien montre des signes évidents de stress ou de peur intenses (halètement excessif, tremblements, tentatives de fuite répétées, gémissements), une agressivité claire (grognements, morsures), ou devient incontrôlable.', '3 succès sur 5 essais consécutifs pour chaque étape clé (manipulation corporelle, yeux, oreilles, gueule).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('marche-zigzag', 'Le slalom en marche est un exercice ludique qui renforce la complicité entre vous et votre chien. Il s''agit de guider votre compagnon à quatre pattes à travers une série de plots disposés en zigzag, tout en marchant à vos côtés. Cet exercice améliore la concentration du chien, sa réactivité à vos demandes et son agilité, tout en étant une excellente activité physique et mentale pour lui. C''est une étape intermédiaire parfaite pour explorer de nouveaux défis ensemble.', NULL, NULL, 'Slalom en marche', 'Suivre un parcours en zigzag', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien effectue le slalom avec fluidité, reste à côté du handler, répond aux commandes vocales et visuelles, et passe entre les plots sans hésitation.', 'Le chien montre des signes de fatigue (halètement excessif, ralentissement), de stress (yeux écarquillés, queue basse), de désintérêt manifeste ou de frustration. Arrêter l''exercice s''il ne progresse plus ou s''il anticipe trop les mouvements de manière non constructive.', '3 succès consécutifs sur 5 essais du parcours complet sans aide.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('slalom-cones', 'Le slalom entre cônes est un excellent exercice pour améliorer la coordination et la concentration de votre chien, tout en renforçant votre complicité. Cet exercice demande à votre chien de passer habilement entre une série de cônes placés en ligne droite ou en courbe. C''est une étape clé pour développer son agilité et sa réactivité à vos guidages. Préparez-vous à passer de bons moments d''apprentissage complices avec votre fidèle compagnon !', NULL, NULL, 'Slalom entre cônes', 'Zigzaguer entre des cônes', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien passe tous les cônes sans en renverser ou les éviter, en suivant le guidage du handler, et ce, avec enthousiasme et concentration.', 'Le chien montre des signes de fatigue, de stress, de désintérêt, ou si l''exercice devient frustrant pour l''un ou l''autre. Arrêtez également si le chien se blesse ou semble inconfortable.', '3 succès consécutifs sur 5 essais sur la totalité du parcours.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/slalom-cones.png'),
('slalom-jambes', 'Le slalom entre les jambes est un exercice ludique qui renforce la complicité entre vous et votre chien. Il améliore l''agilité de votre compagnon tout en lui apprenant à rester concentré sur vous. Cet exercice, une fois maîtrisé, ouvre la voie à des figures plus complexes et à des parcours d''agility.', NULL, NULL, 'Slalom entre les jambes', 'Passer en huit entre les jambes', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute l''exercice avec fluidité, en passant de manière autonome entre les jambes lorsque guidé par le handler, et répond positivement aux commandes.', 'Le chien montre des signes de fatigue, de stress, d''inconfort, ou s''il refuse catégoriquement de continuer l''exercice malgré les encouragements.', 'Le chien doit réussir 3 passages consécutifs entre les jambes sans hésitation, en réagissant aux commandes vocales et corporelles.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('slalom-piquets', 'Le slalom est un excellent exercice pour renforcer la complicité avec votre chien tout en améliorant son agilité et sa concentration. Il consiste à guider votre chien à travers une série de piquets placés en ligne droite ou en courbe. Cet exercice avancé demande de la précision et une bonne communication entre vous et votre compagnon canin, le rendant parfait pour les chiens qui maîtrisent déjà les bases du guidage. Prévoyez environ 10 minutes pour cette séance ludique et stimulante.', NULL, NULL, 'Slalom entre piquets', 'Slalomer entre 6-12 piquets', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien passe correctement entre tous les piquets dans l''ordre, en suivant les indications du handler, sans enfreindre les règles de base de l''agilité (ex: ne pas toucher les piquets intentionnellement pour les faire tomber ou les contourner).', 'Le chien montre des signes de fatigue excessive, de stress, d''inconfort, ou une perte totale d''intérêt. Le handler peut aussi décider d''arrêter si l''exercice devient frustrant pour l''un ou l''autre.', 'Réussir le parcours complet de slalom avec 6 à 12 piquets sans toucher ou contourner un piquet, 3 fois sur 5 essais.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('sociabilite-ring', 'Cet exercice avancé simule un environnement socialement chargé pour votre chien. L''objectif est de lui apprendre à rester détendu et sous contrôle même lorsqu''il est entouré de personnes (figurants) qui bougent et font du bruit. C''est une étape cruciale pour renforcer sa confiance et sa capacité à gérer les situations du quotidien. Le succès dépend de la confiance que votre chien a en vous et de sa compréhension des signaux que vous lui envoyez.', NULL, NULL, 'Sociabilité ring', 'Rester calme parmi les figurants', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste détendu, ne montre pas de signes de stress (halètement excessif, queue basse, oreilles aplaties, vocalisations), et reste attentif à son maître malgré le mouvement et le bruit des figurants.', 'Le chien montre des signes de peur ou d''agressivité incontrôlable, une tentative de fuite désespérée, ou une fatigue excessive. La sécurité et le bien-être du chien sont prioritaires.', '3 succès sur 5 essais, où le chien reste calme et non réactif pendant au moins 30 secondes en présence de 3 figurants actifs.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('socialisation-chiot', 'La socialisation est cruciale pour que votre chiot devienne un chien équilibré et confiant. Cet exercice simple et court vise à l''habituer en douceur à de nouvelles choses : bruits, objets, personnes, autres animaux calmes. L''objectif est de créer des expériences positives pour qu''il associe ces nouveautés à de bons moments. Une bonne socialisation précoce prévient les peurs et les réactions agressives futures.', NULL, NULL, 'Socialisation du chiot', 'Rencontres positives avec divers stimuli', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chiot montre de la curiosité ou reste calme en présence du stimulus, accepte une friandise et montre des signes de détente (corps souple, queue remuant doucement).', 'Le chiot montre des signes de peur intense (queue entre les jambes, halètement excessif, tremblements), d''agressivité (grognements, morsures défensives) ou de fatigue extrême.', '3 succès sur 5 essais d''interaction positive avec différents stimuli.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('cooperative-care', 'Le jeu du seau, également appelé ''soins coopératifs'', est une méthode ludique pour habituer votre chien à accepter les manipulations nécessaires aux soins (brossage, coupe d''ongles, nettoyage des yeux, etc.). Le principe est simple : le chien apprend que le contact avec le seau (ou un objet similaire) est associé à des récompenses agréables. Progressivement, vous associez le toucher de votre chien à des zones spécifiques de son corps, et il apprend à rester calme et consentant, voire à rechercher activement ces moments grâce au renforcement positif.', NULL, NULL, 'Soins coopératifs (Bucket Game', 'Le chien consent aux soins', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne montre pas de signes de stress (halètement excessif, bâillements, morsures de lèvres, oreilles en arrière) et accepte les manipulations proposées sans chercher à les éviter.', 'Signes de stress marqués chez le chien (tentative de fuite, grognement, agressivité légère), absence de réceptivité aux récompenses, ou fatigue évidente du chien.', '3 succès consécutifs sur 5 essais observés dans un environnement différent.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-1h', 'Cet exercice avancé vise à habituer votre chien à rester seul pendant une durée prolongée, atteignant jusqu''à 65 minutes. L''objectif est de construire sa confiance et de réduire l''anxiété de séparation en franchissant une étape significative. Il est crucial de bien préparer le chien et de suivre les étapes avec patience pour garantir le succès de cette première heure complète en solo.', NULL, NULL, 'Solitude 1 heure', 'Première heure seul', 'La constance est la clé du succès', '65 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, détendu et autonome pendant toute la durée de l''exercice, sans manifester de signes d''anxiété ou de détresse.', 'Le chien montre des signes marqués de stress : halètements excessifs, salivation importante, destruction, vocalisations intenses, tentatives de fuite, ou fait ses besoins à l''intérieur.', '3 succès consécutifs sur 5 tentatives réussies, où le chien reste calme pendant toute la durée de l''exercice sans signe de détresse.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-1min', 'Cet exercice aide votre chien à s''habituer à de courtes périodes de solitude, réduisant ainsi l''anxiété de séparation. L''objectif est de lui apprendre que votre départ, même bref, n''est pas alarmant et que vous revenez toujours. C''est une étape fondamentale pour construire sa confiance et son autonomie lorsqu''il est laissé seul.', NULL, NULL, 'Solitude 1 minute', 'Absence d''une minute', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et détendu pendant toute la minute d''absence, sans manifester de stress (aboiements, pleurs, destruction, excitation). Il montre une légère excitation positive à votre retour mais se calme rapidement.', 'Le chien manifeste du stress (halètement excessif, tremblements, vocalisations), tente de gratter la porte, ou montre des signes de panique. Si le chien n''arrive pas à se détendre pendant l''exercice.', '3 succès sur 5 essais avec une absence d''une minute sans signe de détresse.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-10s', 'Cet exercice simple aide votre chien à s''habituer à votre absence, même pour de très courtes périodes. Il pose les bases pour qu''il apprenne à rester calme et en confiance quand vous le quittez. L''objectif est de lui montrer que votre départ est temporaire et qu''il n''y a aucune raison de s''inquiéter. En pratiquant régulièrement, vous construirez sa tolérance à la solitude.', NULL, NULL, 'Solitude 10 secondes', 'Quitter la pièce 10 secondes', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et ne montre pas de signes d''anxiété (aboiements, pleurs, griffures à la porte, destruction) pendant votre absence de 10 secondes.', 'Le chien montre des signes de détresses intenses (halètement excessif, panique, destruction) ou n''arrive pas à se calmer même après votre retour.', '3 succès consécutifs sur 5 essais, sans signe de détresse.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-15min', 'Cet exercice aide votre chien à s''habituer à de courtes périodes de solitude. L''objectif est qu''il associe votre départ à un moment calme et sans inquiétude. Nous allons commencer par de courtes absences, puis augmenter progressivement la durée pour qu''il apprenne à gérer le fait d''être seul. C''est une étape clé pour prévenir l''anxiété de séparation et renforcer son autonomie. Ce programme est conçu pour des chiens qui gèrent déjà bien quelques minutes sans vous.', NULL, NULL, 'Solitude 15 minutes', 'Quart d''heure seul sans stress', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne manifeste pas de vocalises intempestives, ne montre pas de signes de panique ou de destruction durant toute la période d''absence.', 'Aboyer de manière continue, hurler, ou manifester des signes de détresse intense comme de la destruction ou de la malpropreté.', '3 succès consécutifs sur 5 essais à la durée de 15 minutes.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-30min', 'Cet exercice vise à habituer votre chien à rester seul pendant 30 minutes, une étape avancée pour renforcer son autonomie et réduire l''anxiété de séparation. Il s''agit de construire progressivement sa confiance en votre retour, en lui montrant que vos départs sont normaux et que vous revenez toujours. Pour que cela soit réussi, il faut une préparation méticuleuse et une exécution en douceur, en respectant le rythme de chaque chien. C''est un gage de sérénité pour le chien comme pour le propriétaire.', NULL, NULL, 'Solitude 30 minutes', 'Demi-heure d''absence', 'La constance est la clé du succès', '35 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, cherche des occupations (jouet, dodo) et ne montre pas de signes d''anxiété (halètement excessif, destruction, vocalises intenses) pendant l''absence et lors de votre retour.', 'Le chien montre des signes de détresse intenses et continus (destruction, malpropreté, aboiements forts et prolongés, automutilation) dès la première minute de l''absence. Le chien ne se calme pas du tout à votre retour et reste en état d''alerte ou de panique.', '3 succès consécutifs sur 5 essais à la durée cible de 30 minutes, sans signes de détresse majeurs.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-5min', 'Cet exercice vise à aider votre chien à mieux tolérer les courtes périodes de solitude. L''objectif est de lui apprendre qu''il peut rester calme et détendu lorsque vous vous absentez pendant quelques minutes. C''est une étape essentielle pour construire son autonomie et réduire l''anxiété de séparation. La confiance mutuelle est la clé de la réussite.', NULL, NULL, 'Solitude 5 minutes', 'Absence de cinq minutes', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, sans vocalises excessives, sans destruction, et sans signes de panique pendant toute la durée de l''absence.', 'Le chien montre des signes de stress importants (halètement excessif, salivation abondante, destruction, vocalises continues) ou si vous devez intervenir trop souvent pour le calmer.', '3 succès sur 5 essais consécutifs (sans aucune détresse visible)', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('solitude-jardin', 'Cet exercice vise à habituer progressivement votre chien à rester seul et calme dans le jardin, même lorsque vous n''êtes pas visible. Il est crucial de construire cette indépendance en douceur pour éviter l''anxiété de séparation. L''objectif est que votre chien associe le jardin à un lieu de détente en votre absence. Nous allons y aller étape par étape pour que cela reste une expérience positive.', NULL, NULL, 'Solitude au jardin', 'Rester seul dans le jardin', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et observe son environnement sans signe d''anxiété lorsqu''il est laissé seul dans le jardin pendant la durée définie.', 'Le chien montre des signes de stress importants (halètement excessif, aboiements intempestifs, tremblements, destruction).', '3 succès sur 5 essais consécutifs pour chaque durée d''absence augmentée.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('sortie-eau', 'Cet exercice vise à apprendre à votre chien à sortir de l''eau de manière calme et contrôlée, sans un secouement immédiat qui pourrait vous éclabousser. Il s''agit de lui apprendre à attendre votre signal ou simplement à adopter une posture plus détendue avant de se secouer. C''est une étape cruciale pour des sorties de baignade plus agréables, surtout si vous marchez ensuite en voiture ou chez des amis. Le chien apprendra la patience et la retenue dans une situation excitante.', NULL, NULL, 'Sortie de l''eau contrôlée', 'Sortir calmement sans secouer immédiatement', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien sort de l''eau sur commande et attend quelques secondes (évolutif) avant de se secouer, sans agitation excessive.', 'Le chien montre des signes de stress, de fatigue, ou d''agressivité, ou si vous êtes éclaboussé de manière répétée et que le chien ne répond plus aux consignes.', 'Valider l''exercice si le chien parvient à sortir et à attendre au moins 3 secondes avant de se secouer dans 3 séances consécutives.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('sprint-court', 'Le ''Sprint court'' est un exercice dynamique pour renforcer le lien entre vous et votre chien, tout en lui permettant de dépenser son énergie de manière contrôlée. Il s''agit d''une course rapide sur une distance courte (environ 50 mètres), idéale pour travailler son rappel et son impulsion. Cet exercice est parfait pour les chiens dynamiques qui ont besoin d''exprimer leur rapidité et leur agilité dans un cadre sécurisé. Il sollicite à la fois l''obéissance et la condition physique de votre compagnon à quatre pattes.', NULL, NULL, 'Sprint court (50m)', 'Course rapide sur courte distance', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien démarre au signal, court la distance de 50m en restant proche de son maître ou en poursuivant son jouet, et revient au rappel ou s''arrête à la fin de la course.', 'Signes de fatigue excessive, blessure potentielle, détresse ou refus systématique du chien.', '3 succès sur 5 essais', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('stabilite-coup-feu', 'Cet exercice avancé vise à habituer votre chien à rester calme et concentré malgré un bruit soudain et fort, simulant un coup de feu. L''entraînement progressif est essentiel pour ne pas traumatiser le chien et construire une confiance solide. Le but est qu''il associe ce bruit à une situation neutre ou positive, plutôt qu''à une menace.', NULL, NULL, 'Stabilité au coup de feu', 'Rester stable au bruit de détonation', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste assis ou couché (selon la position choisie) de manière détendue, sans sursauter, haleter excessivement, chercher à fuir ou montrer des signes d''anxiété, pendant et immédiatement après le bruit. Il reprend rapidement son état de calme initial.', 'Le chien montre des signes évidents de détresse ou de peur insurmontable (tremblements forts, aboiements de panique, tentative de fuite désespérée). Si l''exercice devient une source de stress répétée pour le chien.', 'Le chien doit réussir 4 fois sur 5 à rester calme et stable (sans réaction de peur, de fuite ou d''anxiété) lors de l''exposition au bruit, à un niveau et une proximité déterminés.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('station-observation', 'La station d''observation est un exercice simple mais essentiel pour aider votre chien à se sentir en sécurité tout en découvrant le monde qui l''entoure. Il s''agit de lui apprendre à rester calme et attentif à une nouvelle situation, comme l''arrivée de quelqu''un ou le passage d''un cycliste, sans réagir de manière excessive. C''est une excellente façon de construire sa confiance et de lui montrer qu''il n''a pas besoin de s''inquiéter de tout ce qu''il voit ou entend. Cet exercice développe sa capacité à gérer les stimulations extérieures de manière positive et relaxée.', NULL, NULL, 'Station d''observation', 'Observer le monde depuis un point sûr', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien observe la distraction calmement, sans tension corporelle excessive, et se reconcentre sur son propriétaire ou reste détendu. Il ne réagit pas de manière alarmée ou agressive.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, tentatives désespérées de fuite), ou s''il est totalement focalisé sur la distraction sans possibilité de le rediriger.', 'Réussir 3 fois de suite, sur 5 séances d''entraînement, sans réaction excessive (tirer, aboyer, grogner) face à une distraction prévisible (personne marchant, vélo passant à distance raisonnable).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('stop-ring-sport', 'Le ''Ring Stop'' est une technique avancée d''éducation canine, particulièrement utile en agility ou en sports canins. Il enseigne au chien à s''arrêter net, quelle que soit sa vitesse ou la direction de sa course. Cet exercice est crucial pour la sécurité et le contrôle du chien, lui permettant de réagir instantanément à un ordre, même dans un environnement stimulant. La maîtrise de cet exercice demande patience et répétition pour garantir une réponse fiable du chien.', NULL, NULL, 'Stop d''arrêt de ring', 'S''arrêter immédiatement en course', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien s''arrête net et immobile immédiatement après la commande ''Stop !'', quelle que soit sa vitesse de course et le niveau de distraction ambiant.', 'Le chien se fige instantanément et garde sa position sans bouger jusqu''à nouvel ordre.', 'Réussir l''exercice 3 fois consécutives dans un environnement donné avant de considérer que la phase est acquise. Puis, valider dans un environnement légèrement différent.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL)
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('stop-urgence', 'Le ''Stop d''urgence'' est une commande essentielle pour la sécurité de votre chien, surtout dans des situations imprévues. Cet exercice avancé apprend à votre chien à s''arrêter net, quelle que soit sa distraction, au son d''un mot clé. Il demande une grande concentration de la part du chien et une parfaite synchronisation avec le maître. Pratiquer régulièrement renforce le lien et assure un contrôle optimal dans toutes les circonstances.', NULL, NULL, 'Stop d''urgence', 'S''arrêter immédiatement en mouvement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien s''immobilise complètement, les quatre pattes au sol, dans les 1 à 2 secondes suivant la commande vocale, indépendamment de l''environnement ou de la distraction.', 'Le chien est incontrôlable, court un danger imminent, ou l''exercice n''apporte plus de bénéfices et devient frustrant pour le chien ou le maître.', '3 succès sur 5 essais, dans des conditions de distraction variables et à différentes allures.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('stop-en-marche', 'Cet exercice, appelé "Stop en marche", est une excellente façon d''apprendre à votre chien à interrompre son mouvement sur commande et à s''asseoir calmement. C''est une compétence essentielle pour la sécurité et le contrôle, qui renforce également votre communication. L''objectif est que votre chien réagisse instantanément à votre signal, créant ainsi un partenariat solide et réactif. Pratiquez dans un environnement calme au début pour maximiser les chances de succès de votre compagnon.', NULL, NULL, 'Stop en marche', 'S''arrêter net et le chien s''assoit', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien s''arrête net dès le signal ''Stop'' (verbal et/ou gestuel) et s''assoit rapidement et calmement, sans délai ni hésitation, et reste en position assise jusqu''au signal de reprise.', 'Le chien ne réagit pas au signal après plusieurs répétitions, montre des signes de stress important (halètement excessif, bâillements, léchage des babines répétés), ou devient totalement démotivé et refuse d''avancer ou de s''arrêter.', '3 succès sur 5 essais sans aide extérieure dans un environnement contrôlé, puis 2 succès sur 3 essais dans un environnement légèrement distrayant.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('stop-troupeau', 'Le ''Stop sur troupeau'' est un exercice essentiel pour enseigner à votre chien l''autocontrôle et la réactivité à votre signal, particulièrement utile dans des contextes impliquant du bétail ou d''autres chiens. Il s''agit de demander au chien de s''arrêter net, peu importe ce qu''il est en train de faire, que ce soit courir, poursuivre ou interagir. Cet exercice renforce votre lien et votre communication, transformant votre chien en un partenaire plus fiable en toutes situations.', NULL, NULL, 'Stop sur troupeau', 'Arrêter le chien en pleine action', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien interrompt son mouvement ou son action sur commande vocale et attend l''ordre de reprise ou la récompense sans se déplacer.', 'Ignorance répétée de la commande, agitation excessive ou prise de fuite ne permettant pas de travailler.', '3 succès sur 5 essais dans des conditions similaires (même niveau de distraction, même distance).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('suite-changement-allure', 'Cet exercice avancé met à l''épreuve la réactivité et le contrôle de votre chien lors de changements d''allure soudains. Vous allez alterner entre marche au pas, trot léger, et une courte course, tout en maintenant une connexion solide avec votre compagnon. L''objectif est de travailler la fluidité des transitions et la compréhension des commandes, y compris le retour au pied après l''effort.', NULL, NULL, 'Suite avec changements d''allur', 'Pas, trot, course et retour', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient une connexion visuelle et une proximité constante lors des changements d''allure, répond promptement et sans hésitation à toutes les commandes vocales, et garde un comportement calme et concentré même durant les phases de course.', 'Le chien montre des signes de fatigue excessive (halètement intense, perte d''enthousiasme), de stress (remuements, bâillements fréquents), ou d''anxiété. Arrêtez immédiatement si le chien est blessé ou s''il refuse complètement de coopérer malgré les encouragements.', '3 succès consécutifs sur 5 essais pour chaque séquence (pas-trot, trot-course, course-rappel, course-pas).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('suite-sans-laisse', 'Cet exercice avancé vise à obtenir une marche au pied impeccable sans laisse, démontrant une confiance et une connexion totale entre vous et votre chien. Le but est que votre chien reste concentré sur vous malgré les distractions potentielles, en restant à votre côté même sans contrainte physique. C''est l''aboutissement d''un travail de longue haleine sur la proprioception, la concentration et le rappel, permettant une liberté sécurisée pour le chien.', NULL, NULL, 'Suite sans laisse', 'Marche au pied parfaite sans laisse', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche de manière fluide et constante à votre côté, regardant souvent vers vous, sans tirer ni s''éloigner. Il répond instantanément aux changements de direction et de rythme, et reste attentif même en présence de distractions contrôlées.', 'Le chien montre des signes de stress (halètement excessif, bâillements répétés, queue basse), une perte totale de concentration, ou s''il réagit de manière incontrôlable aux distractions. Arrêtez également si vous perdez votre calme ou si l''exercice devient frustrant pour vous ou le chien.', 'Réussir 4 séquences de 50 pas consécutifs dans un environnement modérément distrayant sans aucune aide (sans longe, sans récompense systématique).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('surfaces-variees', 'Cet exercice simple et ludique permet à votre chien de s''habituer en douceur à différentes textures sous ses pattes. En le pratiquant, vous aiderez votre compagnon à devenir plus confiant et moins anxieux face aux changements d''environnement. C''est une excellente base pour développer son équilibre et sa confiance en soi, tout en renforçant votre complicité. Nous allons explorer ensemble tapis, gravier, et autres surfaces pour que chaque sortie devienne une aventure positive.', NULL, NULL, 'Surfaces variées', 'Marcher sur grille, eau, sable, etc.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien traverse la surface demandée sans hésitation ni signe de peur, en suivant le handler ou en cherchant la récompense, même pour une courte distance.', 'Le chien montre des signes de stress importants (tremblements, évitement actif, aboiements de peur) malgré les encouragements et les tentatives de simplification.', '3 succès sur 5 essais pour chaque nouvelle surface introduite.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('camera-monitoring', 'Cet exercice consiste à utiliser une caméra de surveillance pour observer comment votre chien se comporte lorsqu''il est seul à la maison. C''est un excellent moyen de comprendre ses réactions, ses habitudes et d''identifier d''éventuels signes de stress ou d''ennui en votre absence. Cela vous permet d''adapter votre environnement ou votre routine pour améliorer son bien-être quand vous n''êtes pas là.', NULL, NULL, 'Surveillance caméra', 'Observer le comportement en votre absence', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Le chien est calme, se repose ou joue seul de manière autonome pendant la majeure partie de votre absence, sans signe de détresse excessive (halètement, destruction, vocalises), et se calme rapidement à votre retour.', 'Le chien montre des signes de panique continus, de destruction systématique, ou une détresse qui ne diminue pas même après plusieurs tentatives d''amélioration. Dans ce cas, une aide professionnelle est recommandée.', 'Observer sur plusieurs absences courtes (15-30 minutes) et quelques absences plus longues (1-2 heures). Chercher une amélioration du comportement d''une séance à l''autre, ou une diminution des signes de stress.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('table-pause', 'La table de pause est un excellent exercice pour apprendre à votre chien à être à l''aise avec la hauteur et à y monter calmement. Cela renforce sa confiance et son apprentissage. C''est aussi une excellente base pour des exercices plus avancés comme la détente sur table ou l''inspection vétérinaire. En rendant cette expérience positive, vous créez un environnement d''apprentissage sécurisant pour votre compagnon à quatre pattes.', NULL, NULL, 'Table de pause', 'Monter et s''asseoir sur la table', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte sur la table avec assurance et s''assoit calmement sur commande, sans hésitation ni stress, et y reste quelques secondes.', 'Le chien montre des signes de peur évidente (tremblements, halètements excessifs, tentative de fuite), l''exercice devient une punition, ou le chien est visiblement fatigué.', '3 succès consécutifs sur 5 essais lors de la phase de montée et d''immobilité assise.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tapis-calme', 'Le tapis de calme est un excellent exercice pour apprendre à votre chien à se détendre et à rester tranquille sur une zone définie. C''est une compétence fondamentale qui peut être utilisée dans de nombreuses situations, que ce soit à la maison, en visite, ou même chez le vétérinaire. En associant le tapis à des expériences positives, vous apprendrez à votre chien à associer cet endroit à la tranquillité et au calme.', NULL, NULL, 'Tapis de calme', 'Se poser sur commande sur le tapis', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien monte calmement sur le tapis sur commande, y reste sans bouger pendant au moins 15 secondes, et ne quitte pas le tapis sans autorisation.', 'Le chien montre des signes de stress ou d''épuisement (halètement excessif, bâillements répétés, tentation de fuir). Arrêtez la séance si vous n''obtenez pas de progrès ou si votre chien est frustré.', '3 succès sur 5 essais consécutifs, où le chien reste sur le tapis pendant au moins 15 secondes sans bouger et sans être distrait.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tapis-fouille', 'Le tapis de fouille est un outil fantastique pour stimuler mentalement votre chien. Il s''agit d''un tapis rempli de bandes de tissu où vous cachez des friandises. Le chien utilise son flair naturel pour trouver toutes les gourmandises cachées, ce qui occupe son esprit et le fatigue agréablement. C''est une activité parfaite pour les jours de pluie ou quand le chien a besoin d''une distraction calme.', NULL, NULL, 'Tapis de fouille (snuffle mat)', 'Chercher des friandises dans le tapis', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement dans le tapis, renifle et trouve la plupart des friandises cachées avec peu ou pas d''aide.', 'Le chien montre clairement des signes de fatigue (halètement excessif, perte d''intérêt, s''endort) ou s''il est distrait par autre chose et ne revient pas à l''activité.', '3 succès sur 5 essais où le chien trouve activement et de manière autonome la majorité des friandises cachées.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tapis-roulant-canin', 'Le tapis roulant canin est un excellent outil pour simuler une promenade ou un trot controlé, idéal pour les chiens manquant d''exercice ou par mauvais temps. Cet exercice avancé permet d''améliorer l''endurance et la concentration de votre chien dans un environnement différent. C''est aussi un bon moyen de travailler l''auto-contrôle et la confiance en soi, en apprenant à votre chien à gérer une machine en mouvement.  Nous allons progresser en douceur pour que cette expérience soit positive pour tous les deux.', NULL, NULL, 'Tapis roulant canin', 'Marche ou trot sur tapis roulant', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte de monter et de se déplacer sur le tapis roulant à une vitesse lui permettant de trotter pendant au moins 5 minutes, sans peur ni contrainte, en restant calme et concentré.', 'Le chien montre des signes évidents de peur, de stress ou de fatigue (halètement excessif, tremblements, refus persistant de bouger, vocalises de détresse), ou s''il tente de sauter du tapis de manière répétée.', 'Valider l''exercice si le chien marche ou trotte sur le tapis roulant pendant 5 minutes consécutives sans signes de stress ou de panique, en restant centré et réceptif aux commandes vocales, sur 3 séances consécutives.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('terrasse-cafe', 'Le concept de la ''Terrasse de café'' simule un environnement extérieur stimulant où votre chien doit apprendre à rester détendu malgré la présence d''autres personnes, de bruits et de mouvements. C''est un exercice d''obéissance avancée qui demande une excellente gestion des distractions et renforce le lien de confiance entre vous et votre chien. L''objectif est de permettre à votre compagnon de vous accompagner sereinement dans des lieux publics, favorisant ainsi une meilleure intégration sociale.', NULL, NULL, 'Terrasse de café', 'Rester calme en terrasse', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien reste couché ou assis calmement à vos pieds pendant 10 minutes dans une terrasse de café moyennement fréquentée, sans aboyer, sans tentative de fuite et sans signes de stress.', 'Le chien montre des signes de stress excessif (halètements importants, tremblements, bâillements répétés, tentatives de fuite) ou devient incontrôlable.', '3 succès sur 5 essais lors de sessions séparées, sans sortie prématurée pour cause de stress.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('courage-test', 'Le test de courage est une épreuve avancée conçue pour évaluer la confiance et la résilience de votre chien face à une situation potentiellement stressante. Un figurant (une personne) adopte une posture menaçante pour voir comment votre chien réagit. C''est un excellent exercice pour renforcer le lien et la confiance mutuelle, à condition d''être réalisé dans un environnement contrôlé et avec une progression adaptée.', NULL, NULL, 'Test de courage', 'Résister face à un figurant menaçant', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, ne montre pas de signe de peur excessive (pas de tentatives de fuite désespérée, pas de tremblements intenses) et peut accepter une approche douce du figurant ou au minimum tolérer sa présence sans paniquer.', 'Le chien montre des signes de peur extrême, une envie irrépressible de fuir, une agressivité incontrôlée, ou si vous sentez que votre chien est dépassé ou en souffrance.', '3 succès sur 5 tentatives, où le chien maintient un comportement calme ou curieux sans signe de peur intense ou d''agressivité.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('toilettage-pro', 'Cet exercice vise à habituer votre chien à un environnement de toilettage potentiellement stressant, en simulant les conditions réelles. L''objectif est de lui apprendre à rester détendu et coopératif pendant que vous ou un professionnel effectuez des soins, comme le brossage, le nettoyage des oreilles ou la coupe des griffes. C''est une étape cruciale pour les chiens qui ont tendance à s''agiter ou à développer de l''anxiété lors de ces manipulations, afin de rendre l''expérience plus agréable pour tous. Une bonne préparation permet de prévenir les réactions négatives futurs et de renforcer le lien de confiance avec votre chien.', NULL, NULL, 'Toilettage professionnel', 'Rester calme chez le toiletteur', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, respirant normalement, sans montrer de signes de stress importants (lèvres retroussées, bâillements excessifs, s''agiter), pendant la majeure partie de la séance de toilettage simulée.', 'Le chien montre des signes évidents de stress (halètement excessif, tremblements, grognements, tentative de fuite répétée) ou un inconfort marqué lors d''une manipulation spécifique.', '3 sessions de réussite consécutives sur 5 tentatives, où le chien reste calme et coopératif pendant les manipulations simulées.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('touche-main', 'Cet exercice vise à apprendre à votre chien à toucher votre main tendue avec son museau. C''est une base essentielle pour de futurs apprentissages et renforce la communication entre vous et votre chien. En jouant, votre chien apprendra à interagir avec vous de manière positive.', NULL, NULL, 'Touche (target main)', 'Toucher la paume de la main avec le nez', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien approche volontairement et touche la main tendue avec son nez suite à la commande vocale.', 'Le chien montre des signes de stress, d''ennui, ou de fatigue (bâillements répétés, se détourne, grogne, s''éloigne).', '3 succès sur 5 essais consécutifs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/3e4414ec-948b-497f-a3fc-f213b286abdf.png'),
('toucher-pattes', 'Cet exercice est conçu pour aider votre chien à être à l''aise avec le toucher de ses pattes, une compétence essentielle pour les soins tels que la coupe des griffes ou le nettoyage. Progressivement, le chien apprendra à rester calme et détendu pendant que vous manipulez ses pattes. Nous allons commencer en douceur, en récompensant chaque petite étape positive de votre chien. Cela renforce la confiance et rend l''expérience agréable pour tous les deux.', NULL, NULL, 'Toucher les pattes', 'Accepter la manipulation des pattes', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et détendu pendant la manipulation des pattes, sans signe de stress ou d''inconfort, et accepte qu''on touche ses pieds pendant plusieurs secondes.', 'Le chien montre des signes clairs de stress (bâillements excessifs, halètement, léchage des babines, oreilles en arrière, queue basse, tentative de fuite) ou refuse catégoriquement de participer.', '3 succès sur 5 essais consécutifs pour chaque étape avant de passer à la suivante.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tourne', 'Apprenez à votre chien à faire un tour sur lui-même en utilisant une friandise comme leurre. Cet exercice simple renforce votre lien et améliore la concentration de votre chien. Commencez dans un endroit calme et sans distractions pour faciliter l''apprentissage.', NULL, NULL, 'Tourne', 'Tourner sur soi-même', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien tourne complètement sur lui-même en suivant la friandise (ou la main vide) après l''exécution de la commande vocale.', 'Le chien montre des signes de fatigue, d''ennui (bâillements excessifs, loss of interest) ou de stress (léchage des babines, oreilles aplaties).', '3 succès consécutifs sur 5 essais pour valider l''acquisition de la commande.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('transition-energie', 'Cet exercice vise à apprendre à votre chien à passer sereinement d''un état d''excitation à un état de calme. C''est une étape cruciale pour renforcer votre complicité et pour gérer les moments où votre chien est trop agité. Nous allons progressivement diminuer son niveau d''énergie en utilisant des signaux clairs et une approche positive. L''objectif est que votre chien associe votre présence et vos demandes à un état de relaxation.', NULL, NULL, 'Transition énergie→calme', 'Passer d''un état excité au calme', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se calme volontairement (s''assoit ou se couche) dès le signal verbal et/ou physique, et y reste quelques secondes en attendant sa récompense. Il ne manifeste plus de signes d''excitation débordante.', 'Le chien montre des signes de fatigue évidente, de stress croissant, ou d''incompréhension répétée malgré les ajustements. Il est préférable de terminer sur une note positive (même simple) et de retenter plus tard.', '3 succès sur 5 essais consécutifs dans un environnement similaire.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('transport-figurant', 'Cet exercice avancé vise à apprendre à votre chien à escorter calmement une personne (votre figurant) dans divers environnements, même s''il y a des distractions. L''objectif est de renforcer le lien de confiance et de contrôle entre vous et votre chien, tout en lui enseignant à rester concentré sur votre guidage. C''est une excellente étape pour préparer votre chien à des situations réelles où le calme et la concentration sont primordiaux, comme des promenades en ville ou des visites dans des lieux publics.', NULL, NULL, 'Transport du figurant', 'Escorter le figurant calmement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche calmement à côté de vous sans tirer, sans réagir de manière excessive au figurant, et reste attentif à vos indications.', 'Le chien montre des signes de stress excessif (halètement, bâillements, tentatives de fuite), des réactions agressives, ou une perte totale de contrôle malgré les corrections.', '3 succès sur 5 essais dans un environnement contrôlé avant d''augmenter la difficulté.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('transport-commun', 'Cet exercice avancé vise à habituer votre chien à rester calme et serein lors des trajets en transports en commun, comme le bus ou le métro. Nous allons simuler l''environnement pour que votre chien associe ces lieux à des moments de calme et de détente, et non à du stress. L''objectif est de construire une généralisation positive, en partant d''un environnement contrôlé pour aller vers des situations plus réalistes. La clé est la progression douce et l''observation attentive de votre animal.', NULL, NULL, 'Transport en commun', 'Rester calme dans les transports', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, détendu, sans vocalise ni tentative de fuite pendant toute la durée du trajet.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, salivation abondante, tentatives de fuite répétées) ou s''il est totalement figé par la peur.', '5 succès sur 7 essais consécutifs lors de simulations ou de trajets courts, sans signe de stress.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('travail-en-binome', 'Cet exercice avancé de coordination en binôme est conçu pour améliorer la communication et la confiance entre deux chiens de sauvetage et leurs maîtres. L''objectif est de travailler simultanément en gardant une harmonie et une compréhension mutuelle, simulant des situations où les chiens doivent agir de concert dans un environnement potentiellement distrayant. Il requiert précision, calme et une excellente lecture des signaux canins.', NULL, NULL, 'Travail en binôme', 'Coordination avec un autre chien de sauvetage', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Les deux chiens maintiennent leur concentration sur leur maître malgré la présence de l''autre chien, exécutent les mouvements demandés de manière coordonnée et sans réactivité excessive.', 'Signes de stress importants chez l''un des chiens (bâillements excessifs, léchage des babines répété, queue basse, tentative de fuite), agressivité entre chiens, perte totale de connexion avec le maître.', '3 succès consécutifs sur 5 essais pour chaque étape clé (échange de regards, mouvement latéral, marche parallèle).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('travail-nocturne', 'Cet exercice avancé permet de familiariser votre chien avec l''environnement nocturne, en renforçant ses aptitudes à rester calme et concentré dans des conditions de faible luminosité. Il s''agit de développer sa confiance lors des promenades nocturnes et de lui apprendre à réagir calmement aux stimuli inhabituels de la nuit. L''objectif est d''assurer des sorties sereines pour vous comme pour lui, même lorsque le soleil est couché et que le monde semble différent.', NULL, NULL, 'Travail nocturne', 'Opérations de nuit avec le chien', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien marche calmement, reste attentif aux commandes vocales et aux signaux de l''humain, et ne montre pas de signes d''anxiété ou de peur excessive face à l''environnement nocturne.', 'Le chien montre des signes importants de peur (tremblements, halètements excessifs, tentatives de fuite) ou d''épuisement. Si l''exercice devient une source de stress majeur pour l''animal.', '3 succès sur 5 essais consécutifs sans signe de stress marqué.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('troupeau-bovins', 'Cet exercice avancé mettra votre chien à l''épreuve avec des bovins plus coopératifs mais toujours exigeants. L''objectif est d''affiner la capacité de votre chien à diriger et à contenir le troupeau efficacement, en développant son discernement et son contrôle. Nous allons travailler sur des scénarios qui demandent plus de finesse et de persévérance, tout en renforçant la confiance et la communication entre vous et votre chien. La durée est de 20 minutes, concentrée sur des manœuvres de conduite plus complexes.', NULL, NULL, 'Travail sur bovins', 'Conduite de bovins (plus résistants)', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien conduit les bovins dans la direction demandée avec fluidité, maintient le troupeau regroupé et contrôlé, réagit de manière appropriée à la résistance des animaux et communique efficacement avec le conducteur.', 'Signes de stress excessif chez le chien ou les bovins, comportement agressif du chien, situation potentiellement dangereuse pour le chien, le conducteur ou les animaux, ou si le chien ne montre aucune capacité à progresser malgré plusieurs tentatives.', '3 succès consécutifs sur 5 tentatives où le troupeau est déplacé dans la direction voulue et regroupé dans la zone cible sans incident majeur.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('troupeau-canards', 'Cet exercice vise à perfectionner la conduite de votre chien sur des canards, des animaux plus réactifs et imprévisibles que d''autres. L''objectif est d''apprendre au chien à rester calme et concentré sur vous malgré la présence de ces proies, développant ainsi son auto-contrôle et sa confiance. Cela nécessite une approche progressive pour éviter de stresser l''animal et de créer des associations négatives.', NULL, NULL, 'Travail sur canards', 'Conduite de canards (plus sensibles)', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, le regard tourné vers le conducteur ou détendu, malgré la présence proactive des canards. Il ne montre pas de signes d''agression ou de poursuite.', 'Le chien montre des signes de stress importants et répétés (halètement excessif, bâillements fréquents, queue basse, oreilles en arrière, tentative de fuite), ou les canards sont visiblement paniqués.', '3 succès consécutifs sur 5 tentatives à une distance donnée, sans réaction excessive.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('traversee-poutre-haute', 'Cet exercice avancé teste la confiance et l''équilibre de votre chien sur une poutre surélevée d''au moins un mètre. Il s''agit de renforcer la coopération et la communication entre vous et votre chien dans un environnement qui demande une concentration accrue. L''objectif est que votre chien traverse la poutre avec assurance, sans hésitation, tout en maintenant une focalisation sur vous. Cet exercice est idéal pour les chiens ayant déjà une bonne base en éducation et souhaitant repousser leurs limites en toute sécurité et confiance.', NULL, NULL, 'Traversée de poutre en hauteur', 'Marcher sur poutre à 1m+', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien monte sur la poutre sans hésitation, la traverse entièrement en maintenant son équilibre et sa concentration sur le handler, et descend calmement à l''arrivée. Le handler n''a pas eu à tirer ou à le porter.', 'Le chien montre des signes clairs de peur, d''anxiété (halètement excessif, bâillements, léchage des babines, queue basse ou rentrée), ou de refus catégorique. Le handler ressent que le chien est en danger de chute ou de blessure.', '3 succès sur 5 traversées complètes à la hauteur et longueur cibles, avec une bonne attitude.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('traversee-passage-pieton', 'Cet exercice vise à apprendre à votre chien à attendre patiemment le signal pour traverser la rue en toute sécurité. L''objectif est d''éviter qu''il ne tire ou ne parte brusquement, favorisant ainsi une traversée calme et maîtrisée. Nous allons travailler la patience, l''obéissance et la confiance mutuelle dans un environnement potentiellement distrayant. C''est une étape cruciale pour garantir la sécurité de votre compagnon lors de vos promenades.', NULL, NULL, 'Traversée de route', 'Attendre et traverser calmement', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste assis ou immobile au bord du trottoir jusqu''au signal de traversée, traverse calmement à côté du maître sans tirer, et attend à nouveau à l''arrivée.', 'Le chien montre des signes évidents de stress (halètement excessif, tremblements, bâillements insistants), une agressivité ou une désobéissance répétée malgré les efforts. Si l''environnement devient trop dangereux ou imprévisible.', '3 succès consécutifs sur 5 tentatives pour valider le niveau.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('treibball', 'Le Treibball est un sport canin ludique où votre chien apprend à pousser de gros ballons vers un but, un peu comme au football mais avec des ballons adaptée à sa taille. C''est une excellente activité pour stimuler mentalement et physiquement votre chien, renforçant sa confiance et votre complicité. Ce niveau intermédiaire vous demande plus de précision dans le guidage et permet à votre chien de mieux anticiper vos directives.', NULL, NULL, 'Treibball', 'Pousser des ballons dans un but', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien pousse volontairement le ballon désigné vers le but, avec un guidage minimal de l''humain, et ce, de manière répétée.', 'Le chien montre des signes évidents de fatigue, de frustration, d''ennui, ou devient incontrôlable. Arrêtez également si l''exercice devient source de stress ou si le chien évite l''activité.', '3 succès sur 5 essais consécutifs pour chaque difficulté introduite.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tri-odeurs', 'Ce jeu évolué mettra vos compétences et celles de votre chien à rude épreuve. Le chien doit apprendre à identifier et à sélectionner une odeur spécifique parmi un mélange d''autres odeurs. C''est un excellent exercice pour aiguiser le flair de votre compagnon et renforcer sa concentration. Il est particulièrement utile pour les chiens destinés à des sports de pistage ou de détection.', NULL, NULL, 'Tri d''odeurs', 'Sélectionner l''odeur correcte parmi plusieurs', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie et signale l''odeur cible de manière claire et répétée, sans se laisser distraire par les autres odeurs.', 'Signes de fatigue excessive, de frustration, de stress, ou si le chien montre des signes de douleur. Dans tous les cas, terminez toujours sur une note positive.', '3 succès consécutifs sur 5 essais à chaque niveau de difficulté.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('distance-confort', 'Cet exercice simple mais fondamental vous aide à comprendre à quel point votre chien se sent à l''aise avec la présence d''autres personnes ou d''autres chiens dans son environnement. En observant attentivement ses réactions et son langage corporel, vous apprendrez à identifier la limite avant qu''il ne commence à se sentir stressé ou mal à l''aise. C''est une étape clé pour construire une relation de confiance et pour pouvoir gérer les situations sociales en toute sécurité.', NULL, NULL, 'Trouver la distance de confort', 'Identifier le seuil de réaction', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ne montre aucun signe de stress (léchage excessif, bâillements, détournement du regard, raideur corporelle, aboiements, grognements) à la distance définie.', 'Le chien montre des signes clairs de stress ou d''inconfort majeurs (agressivité, envie de fuir incontrôlable, tremblements).', '3 succès sur 5 essais, où le chien reste détendu à une détermination de distance ou une proximité avec la source de distraction.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tunnel', 'Le tunnel est un excellent moyen d''initier votre chien à de nouveaux environnements et de renforcer sa confiance. Il apprendra à entrer volontairement dans un espace clos et à en ressortir, le tout en vous faisant confiance. Cet exercice simple est idéal pour les jeunes chiots ou les chiens timides qui découvrent le monde de l''agilité.', NULL, NULL, 'Tunnel', 'Traverser un tunnel', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien traverse le tunnel d''une extrémité à l''autre de manière autonome et avec assurance, sans signe de stress.', 'Le chien montre des signes de peur évidente (refus, tremblements, queue basse, tentatives de fuite) ou se bloque complètement.', '3 succès sur 5 traversées du tunnel, sans aucune hésitation ou peur.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('tunnel-souple', 'Le tunnel souple, souvent appelé ''chute'', est un excellent exercice pour renforcer la confiance de votre chien et son envie d''explorer. Cet obstacle simule une ouverture plus étroite et parfois instable, demandant à votre chien de s''engager activement. C''est une étape logique après la familiarisation avec des tunnels plus larges et rigides, parfait pour un chien qui commence à maîtriser les bases de l''agilité.', NULL, NULL, 'Tunnel souple (chute)', 'Traverser un tunnel avec tissu', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien traverse le tunnel souple de manière autonome, avec enthousiasme et sans signes de peur ou d''hésitation, même avec une légère courbure ou une ouverture réduite.', 'Signes de stress ou de peur avérés (tremblements, halètement excessif, tentative de fuite), refus catégorique de passer, blessure.', '3 succès sur 5 essais consécutifs, sans hésitation majeure.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('u-turn', 'L''U-turn d''évitement est une technique essentielle pour détourner rapidement votre chien d''une situation potentiellement stressante ou excitante.  Il s''agit de faire demi-tour sur soi-même de manière fluide pour s''éloigner d''un objet, d''une personne ou d''un autre animal que votre chien pourrait trouver difficile à gérer. Enseigner cet exercice dès le début renforce la confiance et la communication entre vous et votre chien, le rendant plus réactif à vos indications et plus serein dans diverses situations.', NULL, NULL, 'U-turn d''évitement', 'Demi-tour rapide pour éviter un déclencheur', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien rompt immédiatement son contact visuel avec le déclencheur et fait un demi-tour rapide en direction du conducteur, répondant positivement à la récompense.', 'Le chien montre des signes de stress excessif (bâillements répétés, halètements, queue basse, évitement du regard), ou le conducteur ressent une perte de contrôle ou une frustration importante.', 'Valider l''exercice lorsque le chien réussit 4 U-turns d''affilée avec un déclencheur contrôlé à une distance de 3 mètres.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('va-a-ta-place', 'Cet exercice vise à apprendre à votre chien à se rendre calmement sur son tapis ou panier désigné lorsque vous le lui demandez. C''est une excellente façon de développer son autonomie et de renforcer le lien de confiance entre vous, tout en lui offrant un espace sécurisant où il peut se détendre. En rendant cet apprentissage ludique et positif, vous aidez votre chien à mieux comprendre vos attentes et à y répondre avec plaisir et coopération.', NULL, NULL, 'Va à ta place', 'Aller se coucher sur un tapis désigné', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se rend de manière autonome sur son tapis désigné, y reste calmement pendant au moins 10 secondes, lorsqu''il reçoit la commande vocale et/ou un geste.', 'Le chien montre des signes de stress, d''anxiété ou de fatigue. L''exercice devient une source de frustration pour vous ou votre chien. Le chien ne comprend absolument pas l''exercice malgré plusieurs essais.', '3 succès sur 5 essais consécutifs dans des conditions similaires avant de passer à l''étape suivante.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('velo-skateboard', 'Cet exercice aide votre chien à rester serein et concentré sur vous malgré la présence d''engins roulants comme les vélos et les skateboards. Pour un chien, ces objets peuvent être source d''excitation ou de peur en raison de leur mouvement rapide et imprévisible. L''objectif est d''apprendre à votre compagnon à tolérer leur passage sans réaction excessive, renforçant ainsi sa confiance et votre lien.', NULL, NULL, 'Vélos et skateboards', 'Rester calme face aux engins roulants', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste détendu, ne tire pas sur la laisse, ne manifeste pas de vocalises ni de tentatives de poursuite lorsqu''un vélo ou un skateboard passe à une distance respectueuse.', 'Signes de stress importants chez le chien tels que halètements excessifs, bâillements répétés, léchage des babines, tremblements, tentatives de fuite ou agressivité.', '3 succès sur 5 essais consécutifs à une distance donnée avant d''envisager de réduire la distance.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('veterinaire', 'Cet exercice vise à désensibiliser votre chien à l''environnement stressant du vétérinaire. L''objectif est qu''il associe cette visite à une expérience positive ou du moins neutre, sans peur ni anxiété. Nous allons simuler l''attente de la salle d''attente et les manipulations courantes lors d''une visite. Une approche progressive et positive est essentielle pour la réussite.', NULL, NULL, 'Visite chez le vétérinaire', 'Accepter l''environnement vétérinaire', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et attentif, accepte les manipulations douces sans signe de stress excessif, et montre une attitude positive ou neutre face aux éléments simulés de l''environnement vétérinaire.', 'Signes évidents de stress intense (halètements excessifs, tremblements, bâillements répétés, léchage des babines, tentative de fuite), agressivité ou refus catégorique de coopérer.', '3 succès consécutifs sur 5 tentatives dans des conditions similaires.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('vitesse-tunnel', 'Cet exercice vise à encourager votre chien à traverser un tunnel à toute allure lors de vos séances d''agility ou de jeux. Il est conçu pour les chiens qui connaissent déjà l''entrée et la sortie du tunnel et qui sont à l''aise dedans. L''objectif est de rendre la traversée fluide et rapide, tout en maintenant la confiance et le plaisir de votre chien. C''est un excellent moyen d''améliorer sa vitesse et son engagement dans les parcours d''obstacles.', NULL, NULL, 'Vitesse au tunnel', 'Traverser le tunnel le plus vite possible', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien se précipite dans le tunnel sans hésitation et en ressort avec enthousiasme, cherchant activement sa récompense.', 'Signes de stress ou de peur chez le chien (halètement excessif, s''accroupir, chercher à fuir). Le chien refuse catégoriquement d''entrer dans le tunnel malgré les encouragements.', '3 succès consécutifs sur 5 essais, où le chien traverse le tunnel rapidement et avec énergie.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('wearing', 'Cet exercice, appelé ''Wearing'', est conçu pour entraîner votre chien à rester près de vous et à maintenir le troupeau (dans ce cas, juste vous et votre chien) bien groupé pendant que vous vous déplacez ensemble. Il est essentiel pour établir une communication claire et une coopération fluide entre vous et votre compagnon canin. Le but est que le chien anticipe vos mouvements et se déplace avec fluidité, comme s''il faisait partie d''un seul corps. C''est une excellente étape pour préparer des activités plus complexes comme l''agility ou le travail de troupeau, en renforçant la connexion et la confiance mutuelle.', NULL, NULL, 'Wearing', 'Maintenir le troupeau groupé en mouvement', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste constamment groupé avec le meneur, suit tous les changements de direction sans hésitation ni tiraillement, et maintient la fluidité du mouvement.', 'Le chien montre des signes de stress, d''anxiété, de fatigue excessive, ou une perte totale d''intérêt et de concentration, indiquant que la séance doit se terminer ou être simplifiée.', '3 succès consécutifs sur 5 essais, où le chien maintient une position groupée et suit fluidement pendant au moins 10 pas lors des changements de direction.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('weight-pulling', 'Cette séance d''initiation au weight pulling pour chiens avancés vise à renforcer la confiance et l''endurance de votre compagnon en lui faisant tirer des charges de manière progressive. L''objectif est d''associer le port de charges à une expérience positive, tout en développant sa puissance et sa détermination. Nous commencerons avec un poids très léger pour que le chien comprenne bien le mouvement et augmenterons graduellement pour optimiser son apprentissage en toute sécurité. Cet exercice, d''une durée de 10 minutes, est idéal pour des chiens déjà habitués à l''effort physique et bien encadrés.', NULL, NULL, 'Weight pulling initiation', 'Tirer des charges progressives', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien tire le chariot sur la distance demandée avec une bonne posture corporelle, une traction constante et manifeste une attitude engagée et positive. Il ne montre aucun signe de peur ou de détresse.', 'Signes de fatigue excessive (halètement intense prolongé après l''effort, langue très sortie et sombre), boiterie, perte d''intérêt marquée, anxiété évidente, ou tout changement comportemental inhabituel.', '3 succès consécutifs sur 5 essais pour une charge donnée avant d''envisager une légère augmentation.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('zen-game', 'Le ''Zen Game'', aussi appelé ''C''est Ton Choix'', est un exercice ludique et simple conçu pour les débutants. Il apprend au chien à gérer son excitation en développant sa capacité à rester calme pour obtenir une friandise. Cette méthode renforce la connexion et la communication entre vous et votre chien, en lui montrant que le calme est la clé pour obtenir ce qu''il désire.', NULL, NULL, 'Zen Game (It''s Yer Choice)', 'Le chien se calme pour obtenir la récompense', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien retire sa gueule de la main, détourne le regard, ou se calme visiblement pendant au moins 3 secondes avant que la friandise ne lui soit donnée.', 'Le chien devient frustré, anxieux, mordille ou montre des signes évidents d''inconfort. Si l''exercice devient une source de stress plutôt qu''un apprentissage positif.', '3 succès sur 5 essais consécutifs.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('zone-contact', 'Cet exercice avancé renforce la précision de votre chien à toucher des cibles spécifiques avec une partie de son corps, ici les zones jaunes. Il demande concentration et contrôle de soi de sa part. C''est une excellente manière d''améliorer sa proprioception et sa réactivité à vos indications spécifiques, renforçant ainsi votre communication.', NULL, NULL, 'Zones de contact', 'Toucher les zones jaunes correctement', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien touche la zone jaune désignée avec la partie du corps attendue (nez ou patte, selon le ciblage) dès la commande, de manière autonome et sans hésitation.', 'Le chien montre des signes de fatigue (halètement excessif, léchage des babines répété), de frustration (aboiements, mordillements), ou une perte totale d''intérêt pour l''exercice.', 'Réussir 4 fois sur 5 essais consécutifs dans des conditions proches de celles de l''exercice final (distance, légère distraction).', 'Observer le langage corporel', NULL, NULL, 'tous', NULL)
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;